import{s as Yf,e as Vr}from"./icon-name-kFDeGXCQ--4TVzzrX.js";import{a as Qd}from"./colors-C1Wmnk_L-aAAP9SXj.js";import{X as Qf,N as Jf,f as eh,b as th}from"./Input--5Y_YAC9-ENU-JAMy.js";import{m as nh,e as ah}from"./divider-color-DMMH0ySn-B7JauIP0.js";import{Z as oh,p as ih,f as rh}from"./index-BNZ0vrtB.js";import{r as g,e as Z}from"./index-jIWwRBLr.js";import{O as sh,u as lh}from"./Button-Nxi7HNci-BcUZeA5m.js";import{u as ch}from"./Card-D-CQD3jr-CdozyrcE.js";import{l as dh,q as uh,U as ph}from"./index-B35LPEAD.js";import{T as mh,D as gh,k as fh,i as hh,s as bh,o as _h}from"./index-CcSGVVoo.js";import{g as vh}from"./Code-DdG_DqBQ-WhN2UCKW.js";import{j as l}from"./jsx-runtime-Cfl8ynUo.js";import{r as ni}from"./index-DWDEzXrj.js";import{t as yh}from"./nord-Cm2omLQ2.js";import{j as xh}from"./index-BnNeS_H2.js";import{c as wh}from"./index-CqY9YpN0.js";import{R as tc}from"./ResetTheme-CLF5P7Bf.js";const Ch=JSON.parse(`{"chat":{"name":"Chat","reactTag":"Chat","tags":["ai","interactive"],"odsComponents":["Avatar","BUTTON_COLOR","BUTTON_SIZE","BUTTON_VARIANT","Button","Clipboard","ClipboardTrigger","FileThumbnail","ICON_NAME","Icon","MESSAGE_BUBBLE_VARIANT","MessageBubble","TEXT_PRESET","Text","type FileThumbnailRemoveDetail","PromptInput","PromptInputControls","type PromptInputFileChangeDetails","PromptInputFileUploadButton","PromptInputFiles","type PromptInputInputSubmitDetails","PromptInputSendButton","PromptInputTextControl"],"source":{"css-modules":{"ChatMessage.tsx":"import { Avatar, BUTTON_COLOR, BUTTON_SIZE, BUTTON_VARIANT, Button, Clipboard, ClipboardTrigger, FileThumbnail, ICON_NAME, Icon, MESSAGE_BUBBLE_VARIANT, MessageBubble, TEXT_PRESET, Text } from '@ovhcloud/ods-react';\\nimport classNames from 'classnames';\\nimport { type JSX } from 'react';\\nimport { type Message } from './fakeApi';\\nimport style from './index.module.scss';\\n\\nconst ChatMessage = ({ message, previousAuthor }: { message: Message, previousAuthor?: string }): JSX.Element => {\\n  const isAi = message.author === 'Assistant';\\n\\n  return (\\n    <div className={ classNames(\\n      style['chat-message'],\\n      { [style['chat-message--human']]: !isAi },\\n    )}>\\n      {\\n        previousAuthor !== message.author &&\\n        <div className={ style['chat-message__info'] }>\\n          {\\n            isAi &&\\n            <Avatar>\\n              <Icon name={ ICON_NAME.sparkle } />\\n            </Avatar>\\n          }\\n\\n          <span>\\n            { message.author }\\n          </span>\\n\\n          {\\n            message.createdAt &&\\n            <Text preset={ TEXT_PRESET.small }>\\n              { message.createdAt.toLocaleString('en', { hour: 'numeric', minute: 'numeric' }) }\\n            </Text>\\n          }\\n        </div>\\n      }\\n\\n      <MessageBubble\\n        className={ style['chat-message__bubble'] }\\n        typing={ message.processing }\\n        variant={ isAi ? MESSAGE_BUBBLE_VARIANT.ai : MESSAGE_BUBBLE_VARIANT.human }>\\n        {\\n          message.files && message.files?.length > 0 &&\\n          <div className={ style['chat-message__bubble__files'] }>\\n            {\\n              message.files.map((file, idx) => (\\n                <FileThumbnail\\n                  dismissible={ false }\\n                  file={ file }\\n                  key={ idx } />\\n              ))\\n            }\\n          </div>\\n        }\\n\\n        {\\n          message.content &&\\n          <span className={ style['chat-message__bubble__content'] }>\\n            { message.content }\\n          </span>\\n        }\\n      </MessageBubble>\\n\\n      {\\n        isAi &&\\n        <div className={ style['chat-message__actions'] }>\\n          <Button\\n            aria-label=\\"Like\\"\\n            color={ BUTTON_COLOR.neutral }\\n            size={ BUTTON_SIZE.sm }\\n            variant={ BUTTON_VARIANT.ghost }>\\n            <Icon name={ ICON_NAME.thumbsUp } />\\n          </Button>\\n\\n          <Button\\n            aria-label=\\"Dislike\\"\\n            color={ BUTTON_COLOR.neutral }\\n            size={ BUTTON_SIZE.sm }\\n            variant={ BUTTON_VARIANT.ghost }>\\n            <Icon name={ ICON_NAME.thumbsDown } />\\n          </Button>\\n\\n          <Clipboard\\n            className={ style['chat-message__actions__copy'] }\\n            value={ message.content }>\\n            <ClipboardTrigger className={ style['code__clipboard__trigger'] }>\\n              <Button\\n                className={ style['code__clipboard__trigger__button'] }\\n                color={ BUTTON_COLOR.neutral }\\n                size={ BUTTON_SIZE.sm }\\n                variant={ BUTTON_VARIANT.ghost }>\\n                <Icon name={ ICON_NAME.fileCopy } />\\n              </Button>\\n            </ClipboardTrigger>\\n          </Clipboard>\\n        </div>\\n      }\\n    </div>\\n  );\\n};\\n\\nexport {\\n  ChatMessage,\\n};\\n","fakeApi.ts":"type Message = {\\n  author: string;\\n  content?: string;\\n  createdAt?: Date;\\n  files?: File[];\\n  processing?: boolean;\\n  uuid: string;\\n}\\n\\nconst DEFAULT_MESSAGES: Message[] = [{\\n  author: 'Assistant',\\n  content: 'Welcome to the Chat recipe. Feel free to test the UI behavior by typing anything on your mind below.',\\n  createdAt: new Date(),\\n  uuid: crypto.randomUUID(),\\n}];\\n\\nasync function fetch(): Promise<Message[]> {\\n  return Promise.resolve(DEFAULT_MESSAGES);\\n}\\n\\nasync function post(content?: string, files?: File[]): Promise<Message> {\\n  return Promise.resolve({\\n    author: 'You',\\n    content: content || '',\\n    createdAt: new Date(),\\n    files,\\n    uuid: crypto.randomUUID(),\\n  });\\n}\\n\\nfunction randomInt(min: number, max: number): number {\\n  return Math.floor(Math.random() * (max - min + 1) + min);\\n}\\n\\nexport {\\n  type Message,\\n  fetch,\\n  post,\\n  randomInt,\\n};\\n","index.module.scss":".chat {\\n  display: flex;\\n  flex-flow: column;\\n  row-gap: var(--ods-theme-row-gap);\\n  justify-content: end;\\n  height: inherit;\\n\\n  &__messages {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: calc(var(--ods-theme-row-gap) * 2);\\n    overflow: auto;\\n  }\\n}\\n\\n.chat-message {\\n  display: flex;\\n  flex-flow: column;\\n  row-gap: calc(var(--ods-theme-row-gap) / 2);\\n  align-items: start;\\n\\n  &--human {\\n    align-items: end;\\n  }\\n\\n  &__info {\\n    display: flex;\\n    flex-flow: row;\\n    column-gap: var(--ods-theme-column-gap);\\n    align-items: center;\\n  }\\n\\n  &__bubble {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: calc(var(--ods-theme-row-gap) * 2);\\n\\n    &__content {\\n      white-space: pre-wrap;\\n    }\\n\\n    &__files {\\n      display: grid;\\n      grid-template-columns: 1fr 1fr;\\n      gap: calc(var(--ods-theme-row-gap) / 2) calc(var(--ods-theme-column-gap) / 2);\\n    }\\n  }\\n\\n  &__actions {\\n    display: flex;\\n    flex-flow: row;\\n    column-gap: calc(var(--ods-theme-column-gap) / 2);\\n    margin: 0 calc(var(--ods-theme-outline-offset) * 2) calc(var(--ods-theme-outline-offset) * 2);\\n\\n    &__copy {\\n      background-color: transparent;\\n      padding: 0;\\n    }\\n  }\\n}\\n","index.tsx":"import { FileThumbnail, type FileThumbnailRemoveDetail, PromptInput, PromptInputControls, type PromptInputFileChangeDetails, PromptInputFileUploadButton, PromptInputFiles, type PromptInputInputSubmitDetails, PromptInputSendButton, PromptInputTextControl } from '@ovhcloud/ods-react';\\nimport { type JSX, useEffect, useRef, useState } from 'react';\\nimport { ChatMessage } from './ChatMessage';\\nimport { MessagesProvider, useMessages } from './useMessages';\\nimport style from './index.module.scss';\\n\\nconst PROCESSING_MESSAGE = {\\n  author: 'Assistant',\\n  processing: true,\\n  uuid: crypto.randomUUID(),\\n};\\n\\nconst ChatRoot = (): JSX.Element => {\\n  const [files, setFiles] = useState<File[]>([]);\\n  const [isSubmitting, setIsSubmitting] = useState(false);\\n  const { isReplying, messages, postMessage } = useMessages();\\n  const messageContainerRef = useRef<HTMLDivElement>(null);\\n\\n  useEffect(() => {\\n    if (messageContainerRef.current) {\\n      messageContainerRef.current.lastElementChild?.scrollIntoView({ behavior: 'smooth' });\\n    }\\n  }, [messages]);\\n\\n  function onFileChange({ files }: PromptInputFileChangeDetails): void {\\n    setFiles((currentFiles) => [...currentFiles, ...files]);\\n  }\\n\\n  function onFileRemove({ file }: FileThumbnailRemoveDetail): void {\\n    setFiles((files) => files.filter((f) => f !== file));\\n  }\\n\\n  async function onSubmit({ inputValue }: PromptInputInputSubmitDetails): Promise<void> {\\n    setIsSubmitting(true);\\n\\n    postMessage(inputValue, files)\\n      .then(() => setFiles([]))\\n      .finally(() => setIsSubmitting(false));\\n  }\\n\\n  return (\\n    <div className={ style['chat'] }>\\n      <div\\n        className={ style['chat__messages'] }\\n        ref={ messageContainerRef }>\\n        {\\n          messages.map((message, idx) => (\\n            <ChatMessage\\n              key={ message.uuid }\\n              message={ message }\\n              previousAuthor={ messages[idx - 1]?.author } />\\n          ))\\n        }\\n\\n        {\\n          isReplying &&\\n          <ChatMessage message={ PROCESSING_MESSAGE } />\\n        }\\n      </div>\\n\\n      <PromptInput\\n        fileCollection={ files }\\n        loading={ isSubmitting }\\n        onFileChange={ onFileChange }\\n        onInputSubmit={ onSubmit }>\\n        <PromptInputFiles>\\n          {\\n            files.map((file, idx) => (\\n              <FileThumbnail\\n                file={ file }\\n                key={ idx }\\n                onFileRemove={ onFileRemove } />\\n            ))\\n          }\\n        </PromptInputFiles>\\n\\n        <PromptInputControls>\\n          <PromptInputFileUploadButton multiple />\\n\\n          <PromptInputTextControl />\\n\\n          <PromptInputSendButton />\\n        </PromptInputControls>\\n      </PromptInput>\\n    </div>\\n  );\\n};\\n\\nconst Chat = (): JSX.Element => {\\n  return (\\n    <MessagesProvider>\\n      <ChatRoot />\\n    </MessagesProvider>\\n  );\\n};\\n\\nexport {\\n  Chat,\\n};\\n","useMessages.tsx":"import { type JSX, type ReactNode, createContext, useContext, useEffect, useState } from 'react';\\nimport { type Message, fetch, post, randomInt } from './fakeApi';\\n\\ninterface MessagesProviderProp {\\n  children: ReactNode,\\n}\\n\\ntype MessagesContextType = Omit<MessagesProviderProp, 'children'> & {\\n  isReplying: boolean;\\n  messages: Message[];\\n  postMessage: (content?: string, files?: File[]) => Promise<void>;\\n};\\n\\nconst MessagesContext = createContext<MessagesContextType | undefined>(undefined);\\n\\nfunction MessagesProvider({ children }: MessagesProviderProp): JSX.Element {\\n  const [isReplying, setIsReplying] = useState(false);\\n  const [messages, setMessages] = useState<Message[]>([]);\\n\\n  useEffect(() => {\\n    fetch().then(setMessages);\\n  }, [setMessages]);\\n\\n  async function postMessage(content?: string, files?: File[]): Promise<void> {\\n    return post(content, files)\\n      .then((newMessage) => {\\n        setMessages((prevMessages) => [\\n          ...prevMessages,\\n          newMessage,\\n        ]);\\n        setIsReplying(true);\\n        triggerAiReply();\\n      });\\n  }\\n\\n  // Trying to mimic bi-directional connection with the API\\n  async function triggerAiReply(): Promise<void> {\\n    setTimeout(() => {\\n      setMessages((prevMessages) => [\\n        ...prevMessages,\\n        {\\n          author: 'Assistant',\\n          content: 'Picture this as a clever answer to your previous statements',\\n          createdAt: new Date(),\\n          uuid: crypto.randomUUID(),\\n        },\\n      ]);\\n      setIsReplying(false);\\n    }, randomInt(1000, 3000));\\n  }\\n\\n  return (\\n    <MessagesContext.Provider value={{\\n      isReplying,\\n      messages,\\n      postMessage,\\n    }}>\\n      { children }\\n    </MessagesContext.Provider>\\n  );\\n}\\n\\nfunction useMessages(): MessagesContextType {\\n  const contextValue = useContext(MessagesContext);\\n\\n  if (!contextValue) {\\n    throw new Error('useMessages must be used within a MessagesProvider');\\n  }\\n\\n  return contextValue;\\n}\\n\\nexport {\\n  MessagesProvider,\\n  useMessages,\\n};\\n"},"README.md":"# Chat\\n\\nThe Chat recipe is used to display a complete chat interface, combining user and assistant messages with contextual information and input capabilities.\\n\\nThe Chat is composed of multiple components: Message Bubble, Avatar, and Prompt Input.\\nIt structures messages in a vertical flow, where each message is associated with metadata such as author and timestamp.\\n\\nContextual action buttons positioned below the Message Bubble allow users to quickly interact with the content (e.g. copy, react, reply).\\n\\nUse this recipe when building chat-based experiences such as AI assistants, support conversations, or messaging interfaces.\\nIt is suited for scenarios where users need to exchange messages, understand context through metadata, and interact efficiently within a continuous conversation flow.\\n\\n## Do's & don'ts\\n\\n### Do\\n\\n- Clearly keep differentiation between user and assistant messages.\\n- Provide quick actions (copy, react) where they add value, especially for AI-generated content.\\n- Keep the Prompt Input always accessible so users can quickly continue the conversation without losing context.\\n- Handle long content.\\n- Preserve chronological order and spacing between messages.\\n\\n### Don't\\n\\n- Mix messages styles inconsistently (changing alignement, spacing within the same conversation).\\n- Overload messages with actions. Limit actions to the most relevant ones.\\n- Avoid removing author names.\\n- Break the conversation flow by inserting unrelated UI elements between messages that disrupt reading.\\n- Make the Prompt Input hard to find or access.\\n"}},"config-tile":{"name":"Config Tile","reactTag":"ConfigTile","tags":["interactive"],"odsComponents":["BADGE_COLOR","BADGE_SIZE","Badge","ICON_NAME","Icon","Quantity","QuantityControl","QuantityInput","Radio","RadioControl","RadioGroup","RadioLabel","Select","SelectContent","SelectControl","type SelectCustomItemRendererArg","type SelectCustomOptionRendererArg","TEXT_PRESET","Text","Tile","formatPrice"],"source":{"css-modules":{"index.module.scss":"@use '@ovhcloud/ods-react/style';\\n\\n.config-tile-select-item {\\n  display: flex;\\n  gap: var(--ods-theme-row-gap) var(--ods-theme-column-gap);\\n  align-items: center;\\n}\\n\\n.config-tile {\\n  box-sizing: border-box;\\n  display: flex;\\n  flex-wrap: wrap;\\n  gap: calc(var(--ods-theme-row-gap) * 2) calc(var(--ods-theme-column-gap) * 2);\\n  padding: calc(var(--ods-theme-padding-vertical) * 2) calc(var(--ods-theme-padding-vertical) * 2);\\n  width: 100%;\\n  container-type: inline-size;\\n\\n  &__info {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: calc(var(--ods-theme-row-gap) * 2);\\n    width: 100%;\\n\\n    &__radio {\\n      display: flex;\\n      column-gap: var(--ods-theme-column-gap);\\n      align-items: center;\\n    }\\n\\n    &__features {\\n      display: inline-flex;\\n      flex-flow: row;\\n      flex-wrap: wrap;\\n      gap: var(--ods-theme-row-gap) var(--ods-theme-column-gap);\\n\\n      &__item {\\n        display: inline-flex;\\n        align-items: center;\\n        white-space: nowrap;\\n\\n        &__icon {\\n          color: var(--ods-theme-success-color);\\n        }\\n\\n        &__label {\\n          color: var(--ods-theme-text-color);\\n          font-size: 16px;\\n          font-weight: 700;\\n        }\\n      }\\n    }\\n\\n    @container (width >= #{style.$ods-breakpoint-mobile}) {\\n      flex: 1;\\n    }\\n  }\\n\\n  &__quantity {\\n    flex: 1;\\n\\n    @container (width >= #{style.$ods-breakpoint-mobile}) {\\n      flex: 0;\\n    }\\n  }\\n\\n  &__pricing {\\n    display: flex;\\n    flex: 1;\\n    flex-flow: column;\\n    align-items: end;\\n    white-space: nowrap;\\n\\n    &__from {\\n      color: var(--ods-theme-text-color);\\n      font-size: 14px;\\n      font-weight: 700;\\n    }\\n\\n    &__amount {\\n      color: var(--ods-theme-primary-color);\\n      font-size: 20px;\\n      font-weight: 700;\\n    }\\n\\n    @container (width >= #{style.$ods-breakpoint-mobile}) {\\n      flex: 0;\\n    }\\n  }\\n}\\n","index.tsx":"import { BADGE_COLOR, BADGE_SIZE, Badge, ICON_NAME, Icon, Quantity, QuantityControl, QuantityInput, Radio, RadioControl, RadioGroup, RadioLabel, Select, SelectContent, SelectControl, type SelectCustomItemRendererArg, type SelectCustomOptionRendererArg, TEXT_PRESET, Text, Tile, formatPrice } from '@ovhcloud/ods-react';\\nimport { type JSX, useState } from 'react';\\nimport style from './index.module.scss';\\n\\nconst FEATURES = [\\n  { label: '4', subLabel: 'vCore' },\\n  { label: '8 Go', subLabel: 'RAM' },\\n  { label: '100 Go', subLabel: '' },\\n  { label: '1 day automated backup', subLabel: '' },\\n  { label: 'Unlimited traffic', subLabel: '200 Mbps' },\\n];\\n\\nconst SELECT_OPTIONS = [\\n  { customRendererData: { offer: 'Save 14% per month' }, label: '12 months', value: '12' },\\n  { customRendererData: { offer: 'Save 4% per month' }, label: '6 months', value: '6' },\\n  { label: 'No commitment', value: '0' },\\n];\\n\\nfunction renderSelectItem(label: string, offer?: string): JSX.Element {\\n  return (\\n    <span className={ style[ 'config-tile-select-item' ] }>\\n      { label }\\n\\n      {\\n        offer &&\\n        <Badge\\n          color={ BADGE_COLOR.promotion }\\n          size={ BADGE_SIZE.sm }>\\n          <Icon name={ ICON_NAME.tag } />&nbsp;{ offer }\\n        </Badge>\\n      }\\n    </span>\\n  );\\n}\\n\\nfunction customSelectItemRenderer({ selectedItems, text }: SelectCustomItemRendererArg): JSX.Element {\\n  return renderSelectItem(text, selectedItems[0].customRendererData?.offer);\\n}\\n\\nfunction customSelectOptionRenderer({ customData, label }: SelectCustomOptionRendererArg): JSX.Element {\\n  return renderSelectItem(label, customData?.offer);\\n}\\n\\nconst ConfigTile = (): JSX.Element => {\\n  const [selected, setSelected] = useState(false);\\n\\n  return (\\n    <RadioGroup onValueChange={ ({ value }) => setSelected(value === 'vps-1') }>\\n      <Tile selected={ selected }>\\n        <Radio\\n          className={ style['config-tile'] }\\n          value=\\"vps-1\\">\\n          <div className={ style['config-tile__info'] }>\\n            <div className={ style['config-tile__info__radio'] }>\\n              <RadioControl />\\n\\n              <RadioLabel >\\n                <Text\\n                  as=\\"span\\"\\n                  preset={ TEXT_PRESET.heading5 }>\\n                  VPS 1\\n                </Text>\\n              </RadioLabel>\\n            </div>\\n\\n            <div className={ style['config-tile__info__features'] }>\\n              {\\n                FEATURES.map(({ label, subLabel }, idx) => (\\n                  <span\\n                    className={ style['config-tile__info__features__item'] }\\n                    key={ idx }>\\n                    <Icon\\n                      className={ style['config-tile__info__features__item__icon'] }\\n                      name={ ICON_NAME.check } />\\n\\n                    <span className={ style['config-tile__info__features__item__label'] }>{ label }</span>\\n                    &nbsp;{ subLabel }\\n                  </span>\\n                ))\\n              }\\n            </div>\\n\\n            <Select\\n              defaultValue={ ['12'] }\\n              items={ SELECT_OPTIONS }>\\n              <SelectControl customItemRenderer={ customSelectItemRenderer } />\\n\\n              <SelectContent customOptionRenderer={ customSelectOptionRenderer } />\\n            </Select>\\n          </div>\\n\\n          <div className={ style['config-tile__quantity'] }>\\n            <Quantity\\n              defaultValue=\\"0\\"\\n              min={ 0 }>\\n              <QuantityControl>\\n                <QuantityInput />\\n              </QuantityControl>\\n            </Quantity>\\n          </div>\\n\\n          <div className={ style['config-tile__pricing'] }>\\n            <span className={ style['config-tile__pricing__from'] }>\\n              From\\n            </span>\\n\\n            <span className={ style['config-tile__pricing__amount'] }>\\n              { formatPrice(24.46, 'en-GB', 'EUR') }\\n            </span>\\n\\n            <Text\\n              as=\\"span\\"\\n              preset={ TEXT_PRESET.caption }>\\n              ex. VAT/month\\n            </Text>\\n\\n            <Text\\n              as=\\"span\\"\\n              preset={ TEXT_PRESET.caption }>\\n              or { formatPrice(13.19, 'en-GB', 'EUR') } incl. VAT/month\\n            </Text>\\n          </div>\\n        </Radio>\\n      </Tile>\\n    </RadioGroup>\\n  );\\n};\\n\\nexport {\\n  ConfigTile,\\n};\\n"},"README.md":"# Config Tile\\n\\nThe Config Tile is used to select and configure a product by choosing options, quantities, or variations.\\n\\n## Config Tile\\n\\nThe Config Tile is a selectable tile designed for product configuration. It can include various interactive elements\\nsuch as checkboxes or radio buttons, quantity selectors, and pricing information.\\n\\nUse this recipe when users need to configure the details of a product, for example by choosing options, adjusting\\nquantities, or reviewing price impacts. The Config Tile can be displayed horizontally or vertically to adapt to\\ndifferent contexts.\\n\\n## Location Tile\\n\\nThe Location Tile displays a location (country or city) as a selectable tile. Use it in listings or configuration\\nflows when location details and pricing need to be clearly presented.\\n\\n## Do's & Don'ts\\n\\n### Do\\n\\n- Use Config Tile to let users select, configure or customize a product or service.\\n- Use radio buttons when only one option can be selected, and checkboxes for multiple options.\\n- Use the horizontal layout for dense configuration steps or side-by-side options.\\n- Use the vertical layout when more content or clarity is required.\\n\\n### Don't\\n\\n- Use Config Tile for simple product discovery or marketing content. Use Product Card related recipes instead.\\n- Overload a single tile with too many interactive controls.\\n- Mix selection patterns (radio button and checkbox) within the same group.\\n"}},"dashboard-card":{"name":"Dashboard Card","reactTag":"DashboardCard","tags":["interactive","presentation"],"odsComponents":["BADGE_COLOR","BUTTON_COLOR","BUTTON_SIZE","BUTTON_VARIANT","Badge","Button","CARD_COLOR","Card","Clipboard","ClipboardControl","ClipboardTrigger","Divider","Editable","EditableActions","EditableDisplay","EditableDisplayEmpty","EditableInput","ICON_NAME","Icon","Input","Link","Menu","MenuContent","MenuItem","MenuTrigger","TEXT_PRESET","Text","Tooltip","TooltipContent","TooltipTrigger"],"source":{"css-modules":{"index.module.scss":".dashboard-card {\\n  display: flex;\\n  flex-flow: column;\\n  row-gap: calc(var(--ods-theme-row-gap) * 1.25);\\n  padding: calc(var(--ods-theme-padding-vertical) * 2) calc(var(--ods-theme-padding-horizontal) * 2);\\n  color: var(--ods-theme-text-color);\\n\\n  &__divider {\\n    width: 100%;\\n  }\\n\\n  &__name,\\n  &__id,\\n  &__region,\\n  &__plugins {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: var(--ods-theme-row-gap);\\n  }\\n\\n  &__region {\\n    &__content {\\n      display: flex;\\n      flex-flow: row;\\n      column-gap: calc(var(--ods-theme-column-gap) / 2);\\n      align-items: center;\\n    }\\n  }\\n\\n  &__plugins {\\n    &__content {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: var(--ods-theme-row-gap);\\n\\n      &__plugin {\\n        display: inline-flex;\\n        flex-flow: row;\\n        column-gap: calc(var(--ods-theme-column-gap) / 2);\\n        align-items: center;\\n      }\\n    }\\n  }\\n\\n  &__footer {\\n    display: flex;\\n    flex-flow: row;\\n    column-gap: var(--ods-theme-column-gap);\\n    align-items: start;\\n    justify-content: space-between;\\n\\n    &__actions {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: var(--ods-theme-row-gap);\\n      align-items: start;\\n    }\\n  }\\n}\\n","index.tsx":"import { BADGE_COLOR, BUTTON_COLOR, BUTTON_SIZE, BUTTON_VARIANT, Badge, Button, CARD_COLOR, Card, Clipboard, ClipboardControl, ClipboardTrigger, Divider, Editable, EditableActions, EditableDisplay, EditableDisplayEmpty, EditableInput, ICON_NAME, Icon, Input, Link, Menu, MenuContent, MenuItem, MenuTrigger, TEXT_PRESET, Text, Tooltip, TooltipContent, TooltipTrigger } from '@ovhcloud/ods-react';\\nimport { type JSX, useRef, useState } from 'react';\\nimport style from './index.module.scss';\\n\\nconst DashboardCard = (): JSX.Element => {\\n  const [clusterName, setClusterName] = useState('MyCluster');\\n  const bufferClusterNameRef = useRef(clusterName);\\n\\n  return (\\n    <Card\\n      className={ style['dashboard-card'] }\\n      color={ CARD_COLOR.neutral }>\\n      <Text preset={ TEXT_PRESET.heading4 }>\\n        Cluster Information\\n      </Text>\\n\\n      <Divider className={ style['dashboard-card__divider'] } />\\n\\n      <div className={ style['dashboard-card__name'] }>\\n        <Text\\n          as=\\"span\\"\\n          id=\\"cluster-name\\"\\n          preset={ TEXT_PRESET.label }>\\n          Name\\n        </Text>\\n\\n        <Editable\\n          onCancel={ () => bufferClusterNameRef.current = clusterName }\\n          onSubmit={ () => setClusterName(bufferClusterNameRef.current) }>\\n          <EditableDisplay>\\n            { clusterName || <EditableDisplayEmpty>Empty value</EditableDisplayEmpty> }\\n          </EditableDisplay>\\n\\n          <EditableInput>\\n            <Input\\n              aria-labelledby=\\"cluster-name\\"\\n              autoFocus\\n              defaultValue={ clusterName }\\n              onChange={ (e) => bufferClusterNameRef.current = e.target.value } />\\n          </EditableInput>\\n\\n          <EditableActions />\\n        </Editable>\\n      </div>\\n\\n      <Divider className={ style['dashboard-card__divider'] } />\\n\\n      <div className={ style['dashboard-card__id'] }>\\n        <Text\\n          as=\\"span\\"\\n          id=\\"cluster-id\\"\\n          preset={ TEXT_PRESET.label }>\\n          ID\\n        </Text>\\n\\n        <Clipboard\\n          aria-labelledby=\\"cluster-id\\"\\n          value=\\"b50879e0-735e-44f5-8ff9-d563303039f0\\">\\n          <ClipboardControl />\\n\\n          <ClipboardTrigger />\\n        </Clipboard>\\n      </div>\\n\\n      <Divider className={ style['dashboard-card__divider'] } />\\n\\n      <div className={ style['dashboard-card__region'] }>\\n        <Text\\n          as=\\"span\\"\\n          preset={ TEXT_PRESET.label }>\\n          Region\\n        </Text>\\n\\n        <div className={ style['dashboard-card__region__content'] }>\\n          GRA9\\n          <Badge>\\n            1-AZ\\n            <Tooltip>\\n              <TooltipTrigger asChild>\\n                <Icon\\n                  aria-label=\\"Open tooltip\\"\\n                  name={ ICON_NAME.circleQuestion } />\\n              </TooltipTrigger>\\n\\n              <TooltipContent withArrow>\\n                Single-zone region, ideal for workloads where cost optimisation is a priority.\\n              </TooltipContent>\\n            </Tooltip>\\n          </Badge>\\n        </div>\\n      </div>\\n\\n      <Divider className={ style['dashboard-card__divider'] } />\\n\\n      <div className={ style['dashboard-card__plugins'] }>\\n        <Text\\n          as=\\"span\\"\\n          preset={ TEXT_PRESET.label }>\\n          Admission plugins\\n        </Text>\\n\\n        <div className={ style['dashboard-card__plugins__content'] }>\\n          <div className={ style['dashboard-card__plugins__content__plugin'] }>\\n            Always Pull Images Plugin\\n            <Badge color={ BADGE_COLOR.success }>\\n              Enable\\n            </Badge>\\n          </div>\\n\\n          <div className={ style['dashboard-card__plugins__content__plugin'] }>\\n            Plugin Node Restriction\\n            <Badge color={ BADGE_COLOR.success }>\\n              Enable\\n            </Badge>\\n          </div>\\n\\n          <Link>\\n            Enable/Disable plugins <Icon name={ ICON_NAME.arrowRight } />\\n          </Link>\\n        </div>\\n      </div>\\n\\n      <Divider className={ style['dashboard-card__divider'] } />\\n\\n      <div className={ style['dashboard-card__footer'] }>\\n        <div className={ style['dashboard-card__footer__actions'] }>\\n          <Button\\n            size={ BUTTON_SIZE.sm }\\n            variant={ BUTTON_VARIANT.ghost }>\\n            Reset Cluster\\n          </Button>\\n\\n          <Button\\n            color={ BUTTON_COLOR.critical }\\n            size={ BUTTON_SIZE.sm }\\n            variant={ BUTTON_VARIANT.ghost }>\\n            Delete Cluster\\n          </Button>\\n        </div>\\n\\n        <Menu>\\n          <MenuTrigger asChild>\\n            <Button\\n              size={ BUTTON_SIZE.sm }\\n              variant={ BUTTON_VARIANT.ghost }>\\n              <Icon name={ ICON_NAME.ellipsisVertical } />\\n            </Button>\\n          </MenuTrigger>\\n\\n          <MenuContent withArrow>\\n            <MenuItem value=\\"strategy\\">\\n              Change Deployment Strategy\\n            </MenuItem>\\n\\n            <MenuItem value=\\"logs\\">\\n              View Cluster Logs\\n            </MenuItem>\\n          </MenuContent>\\n        </Menu>\\n      </div>\\n    </Card>\\n  );\\n};\\n\\nexport {\\n  DashboardCard,\\n};\\n"},"tailwind":{"index.module.css":"/* stylelint-disable */\\n@tailwind base;\\n@tailwind components;\\n@tailwind utilities;\\n/* stylelint-enable */\\n","index.tsx":"import { BADGE_COLOR, BUTTON_COLOR, BUTTON_SIZE, BUTTON_VARIANT, Badge, Button, CARD_COLOR, Card, Clipboard, ClipboardControl, ClipboardTrigger, Divider, Editable, EditableActions, EditableDisplay, EditableDisplayEmpty, EditableInput, ICON_NAME, Icon, Input, Link, Menu, MenuContent, MenuItem, MenuTrigger, TEXT_PRESET, Text, Tooltip, TooltipContent, TooltipTrigger } from '@ovhcloud/ods-react';\\nimport { type JSX, useRef, useState } from 'react';\\nimport './index.module.css';\\n\\nconst DashboardCard = (): JSX.Element => {\\n  const [clusterName, setClusterName] = useState('MyCluster');\\n  const bufferClusterNameRef = useRef(clusterName);\\n\\n  return (\\n    <Card\\n      className=\\"flex flex-col gap-y-[calc(var(--ods-theme-row-gap)_*_1.25)] py-[calc(var(--ods-theme-padding-vertical)_*_2)] px-[calc(var(--ods-theme-padding-horizontal)_*_2)] text-[var(--ods-theme-text-color)]\\"\\n      color={ CARD_COLOR.neutral }>\\n      <Text preset={ TEXT_PRESET.heading4 }>\\n        Cluster Information\\n      </Text>\\n\\n      <Divider className=\\"w-full\\" />\\n\\n      <div className=\\"flex flex-col gap-y-[var(--ods-theme-row-gap)]\\">\\n        <Text\\n          as=\\"span\\"\\n          id=\\"cluster-name\\"\\n          preset={ TEXT_PRESET.label }>\\n          Name\\n        </Text>\\n\\n        <Editable\\n          onCancel={ () => bufferClusterNameRef.current = clusterName }\\n          onSubmit={ () => setClusterName(bufferClusterNameRef.current) }>\\n          <EditableDisplay>\\n            { clusterName || <EditableDisplayEmpty>Empty value</EditableDisplayEmpty> }\\n          </EditableDisplay>\\n\\n          <EditableInput>\\n            <Input\\n              aria-labelledby=\\"cluster-name\\"\\n              autoFocus\\n              defaultValue={ clusterName }\\n              onChange={ (e) => bufferClusterNameRef.current = e.target.value } />\\n          </EditableInput>\\n\\n          <EditableActions />\\n        </Editable>\\n      </div>\\n\\n      <Divider className=\\"w-full\\" />\\n\\n      <div className=\\"flex flex-col gap-y-[var(--ods-theme-row-gap)]\\">\\n        <Text\\n          as=\\"span\\"\\n          id=\\"cluster-id\\"\\n          preset={ TEXT_PRESET.label }>\\n          ID\\n        </Text>\\n\\n        <Clipboard\\n          aria-labelledby=\\"cluster-id\\"\\n          value=\\"b50879e0-735e-44f5-8ff9-d563303039f0\\">\\n          <ClipboardControl />\\n\\n          <ClipboardTrigger />\\n        </Clipboard>\\n      </div>\\n\\n      <Divider className=\\"w-full\\" />\\n\\n      <div className=\\"flex flex-col gap-y-[var(--ods-theme-row-gap)]\\">\\n        <Text\\n          as=\\"span\\"\\n          preset={ TEXT_PRESET.label }>\\n          Region\\n        </Text>\\n\\n        <div className=\\"flex flex-row gap-x-[calc(var(--ods-theme-column-gap)_/_2)] items-center\\">\\n          GRA9\\n          <Badge>\\n            1-AZ\\n            <Tooltip>\\n              <TooltipTrigger asChild>\\n                <Icon\\n                  aria-label=\\"Open tooltip\\"\\n                  name={ ICON_NAME.circleQuestion } />\\n              </TooltipTrigger>\\n\\n              <TooltipContent withArrow>\\n                Single-zone region, ideal for workloads where cost optimisation is a priority.\\n              </TooltipContent>\\n            </Tooltip>\\n          </Badge>\\n        </div>\\n      </div>\\n\\n      <Divider className=\\"w-full\\" />\\n\\n      <div className=\\"flex flex-col gap-y-[var(--ods-theme-row-gap)]\\">\\n        <Text\\n          as=\\"span\\"\\n          preset={ TEXT_PRESET.label }>\\n          Admission plugins\\n        </Text>\\n\\n        <div className=\\"flex flex-col gap-y-[var(--ods-theme-row-gap)]\\">\\n          <div className=\\"inline-flex flex-row gap-x-[calc(var(--ods-theme-column-gap)_/_2)] items-center\\">\\n            Always Pull Images Plugin\\n            <Badge color={ BADGE_COLOR.success }>\\n              Enable\\n            </Badge>\\n          </div>\\n\\n          <div className=\\"inline-flex flex-row gap-x-[calc(var(--ods-theme-column-gap)_/_2)] items-center\\">\\n            Plugin Node Restriction\\n            <Badge color={ BADGE_COLOR.success }>\\n              Enable\\n            </Badge>\\n          </div>\\n\\n          <Link>\\n            Enable/Disable plugins <Icon name={ ICON_NAME.arrowRight } />\\n          </Link>\\n        </div>\\n      </div>\\n\\n      <Divider className=\\"w-full\\" />\\n\\n      <div className=\\"flex flex-row gap-x-[var(--ods-theme-column-gap)] items-start justify-between\\">\\n        <div className=\\"flex flex-col gap-y-[var(--ods-theme-row-gap)] items-start\\">\\n          <Button\\n            size={ BUTTON_SIZE.sm }\\n            variant={ BUTTON_VARIANT.ghost }>\\n            Reset Cluster\\n          </Button>\\n\\n          <Button\\n            color={ BUTTON_COLOR.critical }\\n            size={ BUTTON_SIZE.sm }\\n            variant={ BUTTON_VARIANT.ghost }>\\n            Delete Cluster\\n          </Button>\\n        </div>\\n\\n        <Menu>\\n          <MenuTrigger asChild>\\n            <Button\\n              size={ BUTTON_SIZE.sm }\\n              variant={ BUTTON_VARIANT.ghost }>\\n              <Icon name={ ICON_NAME.ellipsisVertical } />\\n            </Button>\\n          </MenuTrigger>\\n\\n          <MenuContent withArrow>\\n            <MenuItem value=\\"strategy\\">\\n              Change Deployment Strategy\\n            </MenuItem>\\n\\n            <MenuItem value=\\"logs\\">\\n              View Cluster Logs\\n            </MenuItem>\\n          </MenuContent>\\n        </Menu>\\n      </div>\\n    </Card>\\n  );\\n};\\n\\nexport {\\n  DashboardCard,\\n};\\n"},"README.md":"# Dashboard Card\\n\\nThe Dashboard Card is used to group and present related dashboard content in a focused area, giving users quick access\\nto essential information and optional actions.\\n"}},"data-grid":{"name":"Data Grid","reactTag":"DataGrid","tags":["interactive","presentation"],"odsComponents":["BUTTON_SIZE","BUTTON_VARIANT","Button","Clipboard","ClipboardControl","ClipboardTrigger","DataTable","DataTableBody","type DataTableColumnDef","type DataTableColumnVisibilityState","DataTableEmpty","DataTableHead","type DataTableRowSelectionState","ICON_NAME","INPUT_TYPE","Icon","Input","Menu","MenuContent","MenuGroup","MenuItem","MenuTrigger","PAGINATION_PER_PAGE","Pagination","PaginationPageSizeSelector","PaginationPages","Popover","PopoverContent","PopoverTrigger","TreeView","TreeViewNode","TreeViewNodes","type TreeViewProp","type TreeViewValueChangeDetail",""],"source":{"css-modules":{"index.module.scss":".data-grid {\\n  display: flex;\\n  flex-flow: column;\\n  row-gap: calc(var(--ods-theme-row-gap) * 2);\\n\\n  &__toolbar {\\n    display: flex;\\n    flex-flow: row;\\n    column-gap: var(--ods-theme-column-gap);\\n    justify-content: space-between;\\n\\n    &__search {\\n      display: flex;\\n      flex-flow: row;\\n      column-gap: var(--ods-theme-column-gap);\\n    }\\n  }\\n\\n  &__table {\\n    max-height: 500px;\\n    overflow: auto;\\n\\n    &__cell {\\n      &__action-menu {\\n        text-align: center;\\n      }\\n    }\\n  }\\n\\n  &__pagination {\\n    align-self: center;\\n  }\\n}\\n","index.tsx":"import {\\n  BUTTON_SIZE,\\n  BUTTON_VARIANT,\\n  Button,\\n  Clipboard,\\n  ClipboardControl,\\n  ClipboardTrigger,\\n  DataTable,\\n  DataTableBody,\\n  type DataTableColumnDef,\\n  type DataTableColumnVisibilityState,\\n  DataTableEmpty,\\n  DataTableHead,\\n  type DataTableRowSelectionState,\\n  ICON_NAME,\\n  INPUT_TYPE,\\n  Icon,\\n  Input,\\n  Menu,\\n  MenuContent,\\n  MenuGroup,\\n  MenuItem,\\n  MenuTrigger,\\n  PAGINATION_PER_PAGE,\\n  Pagination,\\n  PaginationPageSizeSelector,\\n  PaginationPages,\\n  Popover,\\n  PopoverContent,\\n  PopoverTrigger,\\n  TreeView,\\n  TreeViewNode,\\n  TreeViewNodes,\\n  type TreeViewProp,\\n  type TreeViewValueChangeDetail,\\n} from '@ovhcloud/ods-react';\\nimport { type FormEvent, type JSX, useEffect, useMemo, useState } from 'react';\\nimport style from './index.module.scss';\\n\\ntype Person = {\\n  age: number;\\n  firstName: string;\\n  id: string;\\n  ip: string;\\n  lastName: string;\\n};\\n\\nconst PAGE_LIMIT = PAGINATION_PER_PAGE.option_10;\\n\\nconst columns: DataTableColumnDef<Person>[] = [\\n  { accessorKey: 'firstName', header: 'First Name', id: 'firstName' },\\n  { accessorKey: 'lastName', header: 'Last Name', id: 'lastName' },\\n  { accessorKey: 'age', header: 'Age', id: 'age' },\\n  {\\n    accessorKey: 'ip',\\n    cell: ({ cell }) => (\\n      <Clipboard value={ cell.getValue<string>() }>\\n        <ClipboardControl />\\n        <ClipboardTrigger />\\n      </Clipboard>\\n    ),\\n    header: 'IP Address',\\n    id: 'ip',\\n    sortingFn: (rowA, rowB, columnId): number => {\\n      const valueA = rowA.getValue<string>(columnId).split('.').map((num) => (\`000\${num}\`).slice(-3) ).join('');\\n      const valueB = rowB.getValue<string>(columnId).split('.').map((num) => (\`000\${num}\`).slice(-3) ).join('');\\n\\n      return Number(valueA) - Number(valueB);\\n    },\\n  },\\n  {\\n    cell: () => (\\n      <div className={ style['data-grid__table__cell__action-menu'] }>\\n        <Menu>\\n          <MenuTrigger asChild>\\n            <Button\\n              size={ BUTTON_SIZE.sm }\\n              variant={ BUTTON_VARIANT.ghost }>\\n              <Icon name={ ICON_NAME.ellipsisVertical } />\\n            </Button>\\n          </MenuTrigger>\\n\\n          <MenuContent withArrow>\\n            <MenuGroup>\\n              <MenuItem value=\\"refresh-ip\\">\\n                Refresh IP address\\n              </MenuItem>\\n\\n              <MenuItem value=\\"send-email\\">\\n                Send an email\\n              </MenuItem>\\n            </MenuGroup>\\n\\n            <MenuItem value=\\"disable-account\\">\\n              Disable account\\n            </MenuItem>\\n          </MenuContent>\\n        </Menu>\\n      </div>\\n    ),\\n    header: 'Actions',\\n    id: 'menu',\\n    size: 50,\\n  },\\n];\\n\\nasync function fetchData(page: number, pageSize: number, query: string): Promise<{ total: number, users: Person[] }> {\\n  const url = \`https://dummyjson.com/users\${query ? \`/search?q=\${query}&\` : '?'}limit=\${pageSize}&skip=\${pageSize * (page - 1)}&select=age,firstName,id,ip,lastName\`;\\n\\n  return fetch(url)\\n    .then((res) => res.json())\\n    .then(({ total, users }) => ({\\n      total,\\n      users,\\n    }));\\n}\\n\\nconst ColumnSelector = ({ onValueChange }: Pick<TreeViewProp, 'onValueChange'>): JSX.Element => {\\n  const items = useMemo(() => [{\\n    children: (columns || []).map((column) => ({\\n      id: column.id,\\n      name: column.header as string,\\n    })),\\n    id: 'select-all',\\n    name: 'Select all',\\n  }], []);\\n\\n  return (\\n    <TreeView\\n      defaultValue={ ['age', 'firstName', 'ip', 'lastName', 'menu'] }\\n      defaultExpandedValue={ ['select-all'] }\\n      items={ items }\\n      multiple\\n      onValueChange={ onValueChange }>\\n      <TreeViewNodes>\\n        {\\n          items.map((item) => (\\n            <TreeViewNode\\n              item={ item }\\n              key={ item.id } />\\n          ))\\n        }\\n      </TreeViewNodes>\\n    </TreeView>\\n  );\\n};\\n\\nconst DataGrid = (): JSX.Element => {\\n  const [currentPage, setCurrentPage] = useState(1);\\n  const [data, setData] = useState<Person[]>(Array(PAGE_LIMIT).fill({}));\\n  const [isLoading, setIsLoading] = useState(false);\\n  const [pageSize, setPageSize] = useState(PAGE_LIMIT);\\n  const [searchQuery, setSearchQuery] = useState('');\\n  const [selection, setSelection] = useState<DataTableRowSelectionState>({});\\n  const [total, setTotal] = useState(0);\\n  const [visibleColumn, setVisibleColumn] = useState<DataTableColumnVisibilityState>({});\\n  const nbSelected = Object.keys(selection).length;\\n\\n  useEffect(() => {\\n    updateData(currentPage, pageSize, searchQuery);\\n  }, [currentPage, pageSize, searchQuery]);\\n\\n  function onColumnSelectionChange({ value }: TreeViewValueChangeDetail): void {\\n    setVisibleColumn(() => columns.reduce<DataTableColumnVisibilityState>((res, column) => {\\n      if (value.indexOf(column.id) >= 0) {\\n        return res;\\n      }\\n      res[column.id] = false;\\n      return res;\\n    }, {}));\\n  }\\n\\n  function onSearch(event: FormEvent): void {\\n    event.preventDefault();\\n\\n    const formData = new FormData(event.target as HTMLFormElement);\\n    const query = formData.get('query') as string;\\n\\n    setSearchQuery(query || '');\\n  }\\n\\n  async function updateData(page: number, limit: number, query: string): Promise<void> {\\n    setIsLoading(true);\\n\\n    return fetchData(page, limit, query).then(({ total, users }) => {\\n      setData(users);\\n      setTotal(total);\\n\\n      // Simulate a bit of network latency\\n      setTimeout(() => {\\n        setIsLoading(false);\\n      }, 1000);\\n    });\\n  }\\n\\n  return (\\n    <div className={ style['data-grid'] }>\\n      <div className={ style['data-grid__toolbar'] }>\\n        <div className={ style['data-grid__toolbar__actions'] }>\\n          <Menu>\\n            <MenuTrigger asChild>\\n              <Button\\n                size={ BUTTON_SIZE.sm }\\n                variant={ BUTTON_VARIANT.outline }>\\n                Export in CSV <Icon name={ ICON_NAME.download } />\\n              </Button>\\n            </MenuTrigger>\\n\\n            <MenuContent withArrow>\\n              <MenuItem\\n                onSelect={ () => alert('Export all in CSV file') }\\n                value=\\"export-all\\">\\n                Export all\\n              </MenuItem>\\n\\n              <MenuItem\\n                onSelect={ () => alert(\`Export \${nbSelected} element(s) in CSV file\`) }\\n                value=\\"export-selection\\">\\n                Export selection ({ nbSelected })\\n              </MenuItem>\\n            </MenuContent>\\n          </Menu>\\n        </div>\\n\\n        <div className={ style['data-grid__toolbar__search'] }>\\n          <Button\\n            onClick={ () => updateData(currentPage, pageSize, searchQuery) }\\n            size={ BUTTON_SIZE.sm }\\n            variant={ BUTTON_VARIANT.outline }>\\n            <Icon name={ ICON_NAME.refresh } />\\n          </Button>\\n\\n          <form onSubmit={ onSearch }>\\n            <Input\\n              clearable\\n              name=\\"query\\"\\n              type={ INPUT_TYPE.search } />\\n          </form>\\n\\n          <Popover>\\n            <PopoverTrigger asChild>\\n              <Button\\n                size={ BUTTON_SIZE.sm }\\n                variant={ BUTTON_VARIANT.outline }>\\n                <Icon name={ ICON_NAME.columns } /> Columns ({ columns.length - Object.keys(visibleColumn).length })\\n              </Button>\\n            </PopoverTrigger>\\n\\n            <PopoverContent withArrow>\\n              <ColumnSelector onValueChange={ onColumnSelectionChange } />\\n            </PopoverContent>\\n          </Popover>\\n        </div>\\n      </div>\\n\\n      <div className={ style['data-grid__table'] }>\\n        <DataTable\\n          columns={ columns }\\n          data={ data }\\n          enableRowSelection\\n          getRowId={ (row) => row.id }\\n          loading={ isLoading }\\n          onRowSelectionChange={ setSelection }\\n          state={{\\n            columnVisibility: visibleColumn,\\n            rowSelection: selection,\\n          }}\\n          stickyHeader>\\n          <DataTableHead />\\n\\n          <DataTableBody />\\n\\n          <DataTableEmpty>\\n            No result found.\\n          </DataTableEmpty>\\n        </DataTable>\\n      </div>\\n\\n      <Pagination\\n        className={ style['data-grid__pagination'] }\\n        onPageChange={ ({ page }) => setCurrentPage(page) }\\n        onPageSizeChange={ ({ pageSize }) => setPageSize(pageSize) }\\n        page={ currentPage }\\n        pageSize={ pageSize }\\n        totalItems={ total }>\\n        <PaginationPageSizeSelector />\\n\\n        <PaginationPages />\\n      </Pagination>\\n    </div>\\n  );\\n};\\n\\nexport {\\n  DataGrid,\\n};\\n"},"README.md":"# Data Grid\\n\\nThis recipe builds on the Data Table component to provide a complete, interactive data grid experience.\\nIt comes with a toolbar that includes search, action buttons, as well as pagination controls and per-row action menus.\\n\\nUse this recipe when you need to present structured data that users can explore and interact with efficiently.\\nIt is particularly suited for dashboards, admin panels, or any interface requiring data management.\\n\\nUse Cases:\\n- Displaying user or product lists in an admin panel\\n- Allowing users to filter, sort, and select rows for bulk actions\\n- Exporting data subsets for reporting or external use\\n- Showing detailed datasets with interactive actions per row\\n"}},"data-grid-with-query-filter":{"name":"Data Grid With Query Filter","reactTag":"DataGridWithQueryFilter","tags":["interactive","presentation"],"odsComponents":["DataTable","DataTableBody","type DataTableColumnDef","DataTableEmpty","DataTableHead","Pagination","QueryFilter","QueryFilterClear","QueryFilterContent","QueryFilterControl","type QueryFilterItem","type QueryFilterOption","type QueryFilterProperty","QueryFilterTags","formatRelativeTime",""],"source":{"css-modules":{"fakeApi.ts":"type Instance = {\\n  backup: string;\\n  image: string;\\n  location: string;\\n  model: string;\\n  startDate: Date;\\n  uuid: string;\\n};\\n\\nconst BACKUPS = ['rotation 7', 'rotation 14', 'custom'];\\nconst IMAGES = ['almalinux', 'centos', 'cloudlinux', 'debian', 'fedora', 'freebsd', 'rockylinux', 'ubuntu'];\\nconst LOCATIONS = ['Gravelines (GRA)', 'Roubaix(RBX-A)', 'Strasbourg (SBG)', 'Frankfurt (DE1)', 'London (UK1)', 'Warsaw (WAW1)', 'Beauharnois (BHS5)', 'Sydney (SYD1)', 'Singapore (SGP1)'];\\nconst MODELS = ['b3-16', 'b3-32', 'b3-64', 'c3-16', 'c3-32'];\\nconst TIMESTAMPS = ['a day', 'a week', 'a month'];\\n\\nasync function fetchFilterValues(): Promise<{\\n  backups: string[],\\n  images: string[],\\n  locations: string[],\\n  models: string[],\\n  timestamps: string[],\\n}> {\\n  return Promise.resolve({\\n    backups: BACKUPS,\\n    images: IMAGES,\\n    locations: LOCATIONS,\\n    models: MODELS,\\n    timestamps: TIMESTAMPS,\\n  });\\n}\\n\\nfunction generateDummyData(): Instance[] {\\n  const nbLoop = randomInt(100, 500);\\n  const data: Instance[] = [];\\n\\n  for (let i = 0; i < nbLoop; i++) {\\n    data.push({\\n      backup: BACKUPS[randomInt(0, BACKUPS.length - 1)],\\n      image: IMAGES[randomInt(0, IMAGES.length - 1)],\\n      location: LOCATIONS[randomInt(0, LOCATIONS.length - 1)],\\n      model: MODELS[randomInt(0, MODELS.length - 1)],\\n      startDate: new Date(randomInt(Date.now() - 7884000000, Date.now())),\\n      uuid: crypto.randomUUID(),\\n    });\\n  }\\n\\n  return data;\\n}\\n\\nfunction getTimeValue(timestamp: string): number {\\n  switch (timestamp) {\\n    case 'a day':\\n      return Date.now() - 86400000;\\n    case 'a week':\\n      return Date.now() - 604800000;\\n    case 'a month':\\n      return Date.now() - 2628000000;\\n    default:\\n      return 0;\\n  }\\n}\\n\\nfunction randomInt(min: number, max: number): number {\\n  return Math.floor(Math.random() * (max - min + 1) + min);\\n}\\n\\nasync function search(page: number, pageSize: number, filters: string[][]): Promise<{ instances: Instance[], total: number }> {\\n  const pageStart = Math.abs((page - 1)) * pageSize;\\n\\n  const filteredData = DATA.filter((instance) => {\\n    return filters.every((filter) => {\\n      const [property, operator, value] = filter;\\n\\n      if (!property || !operator || !value) {\\n        return false;\\n      }\\n\\n      switch (operator) {\\n        case '=':\\n          return instance[property as keyof Instance] === value;\\n        case '!=':\\n          return instance[property as keyof Instance] !== value;\\n        case '<':\\n          return (instance[property as keyof Instance] as Date).getTime() >= getTimeValue(value);\\n        case '>':\\n          return (instance[property as keyof Instance] as Date).getTime() <= getTimeValue(value);\\n        default:\\n          return false;\\n      }\\n    });\\n  });\\n\\n  return withDelay(Promise.resolve({\\n    instances: filteredData.slice(pageStart, pageStart + pageSize),\\n    total: filteredData.length,\\n  }));\\n}\\n\\nasync function withDelay<T>(promise: Promise<T>): Promise<T> {\\n  return new Promise((resolve) => {\\n    setTimeout(() => resolve(promise), randomInt(500, 2000));\\n  });\\n}\\n\\nconst DATA = generateDummyData();\\n\\nexport {\\n  type Instance,\\n  fetchFilterValues,\\n  search,\\n};\\n","index.module.scss":".data-grid-with-query-filter {\\n  display: flex;\\n  flex-flow: column;\\n  row-gap: calc(var(--ods-theme-row-gap) * 2);\\n\\n  &__toolbar {\\n    display: flex;\\n    align-items: end;\\n\\n    &__control {\\n      width: 300px;\\n    }\\n\\n    &__filters {\\n      display: flex;\\n      gap: var(--ods-theme-row-gap) var(--ods-theme-column-gap);\\n      align-items: center;\\n\\n      &__tags {\\n        justify-content: end;\\n      }\\n    }\\n  }\\n\\n  &__table {\\n    max-height: 500px;\\n    overflow: auto;\\n  }\\n\\n  &__pagination {\\n    align-self: center;\\n  }\\n}\\n","index.tsx":"import {\\n  DataTable,\\n  DataTableBody,\\n  type DataTableColumnDef,\\n  DataTableEmpty,\\n  DataTableHead,\\n  Pagination,\\n  QueryFilter,\\n  QueryFilterClear,\\n  QueryFilterContent,\\n  QueryFilterControl,\\n  type QueryFilterItem,\\n  type QueryFilterOption,\\n  type QueryFilterProperty,\\n  QueryFilterTags,\\n  formatRelativeTime,\\n} from '@ovhcloud/ods-react';\\nimport { type JSX, type ReactNode, useEffect, useState } from 'react';\\nimport { type Instance, fetchFilterValues, search } from './fakeApi';\\nimport style from './index.module.scss';\\n\\nconst PAGE_SIZE = 5;\\n\\nconst columns: DataTableColumnDef<Instance>[] = [\\n  { accessorKey: 'uuid', header: 'Instance ID', id: 'uuid' },\\n  { accessorKey: 'location', header: 'Location', id: 'location' },\\n  { accessorKey: 'model', header: 'Model', id: 'model' },\\n  { accessorKey: 'image', header: 'Image', id: 'image' },\\n  { accessorKey: 'backup', header: 'Backup Logic', id: 'backup' },\\n  {\\n    accessorKey: 'startDate',\\n    cell: ({ cell }): ReactNode => {\\n      const value = cell.getValue<Date>();\\n      if (value) {\\n        return formatRelativeTime(value, 'en');\\n      }\\n    },\\n    header: 'Running since',\\n    id: 'startDate',\\n  },\\n];\\n\\nconst queryFilterProperty = {\\n  label: 'Properties',\\n  options: [\\n    { label: 'Location', value: 'location' },\\n    { label: 'Model', value: 'model' },\\n    { label: 'Image', value: 'image' },\\n    { label: 'Backup Logic', value: 'backup' },\\n    { label: 'Running since', value: 'startDate' },\\n  ],\\n};\\n\\nfunction getFilterOption(values: string[], operators?: QueryFilterItem[]): { operator: QueryFilterProperty, value: QueryFilterProperty } {\\n  return {\\n    operator: {\\n      label: 'Operators',\\n      options: operators || [\\n        { label: 'equals', value: '=' },\\n        { label: 'not equals', value: '!=' },\\n        { label: 'contains', value: 'has' },\\n      ],\\n    },\\n    value: {\\n      label: 'Values',\\n      options: values.map((value) => ({\\n        label: value,\\n        value: value,\\n      })),\\n    },\\n  };\\n}\\n\\nconst DataGridWithQueryFilter = (): JSX.Element => {\\n  const [currentPage, setCurrentPage] = useState(1);\\n  const [data, setData] = useState<Instance[]>(Array(PAGE_SIZE).fill({}));\\n  const [filters, setFilters] = useState<string[][]>([]);\\n  const [isLoading, setIsLoading] = useState(false);\\n  const [queryFilterOption, setQueryFilterOption] = useState<QueryFilterOption>({});\\n  const [total, setTotal] = useState(0);\\n\\n  useEffect(() => {\\n    fetchFilterValues()\\n      .then(({ backups, images, locations, models, timestamps }) => {\\n        setQueryFilterOption({\\n          backup: getFilterOption(backups),\\n          image: getFilterOption(images),\\n          location: getFilterOption(locations),\\n          model: getFilterOption(models),\\n          // status: getFilterOption(statuses),\\n          startDate: getFilterOption(timestamps, [\\n            { label: 'less than', value: '<' },\\n            { label: 'more than', value: '>' },\\n          ]),\\n        });\\n      });\\n  }, [setQueryFilterOption]);\\n\\n  useEffect(() => {\\n    updateData(currentPage, filters);\\n  }, [currentPage, filters]);\\n\\n  async function updateData(page: number, filters: string[][]): Promise<void> {\\n    setIsLoading(true);\\n\\n    return search(page, PAGE_SIZE, filters).then(({ instances, total }) => {\\n      setData(instances);\\n      setTotal(total);\\n      setIsLoading(false);\\n    });\\n  }\\n\\n  return (\\n    <div className={ style['data-grid-with-query-filter'] }>\\n      <QueryFilter\\n        className={ style['data-grid-with-query-filter__toolbar'] }\\n        filterOption={ queryFilterOption }\\n        filterProperty={ queryFilterProperty }\\n        onValueChange={ ({ value }) => setFilters(value) }>\\n        <QueryFilterControl className={ style['data-grid-with-query-filter__toolbar__control'] } />\\n\\n        <QueryFilterContent />\\n\\n        {\\n          filters.length > 0 &&\\n          <div className={ style['data-grid-with-query-filter__toolbar__filters'] }>\\n            <QueryFilterTags className={ style['data-grid-with-query-filter__toolbar__filters__tags'] } />\\n\\n            <QueryFilterClear>\\n              Clear filters\\n            </QueryFilterClear>\\n          </div>\\n        }\\n      </QueryFilter>\\n\\n      <div className={ style['data-grid-with-query-filter__table'] }>\\n        <DataTable\\n          columns={ columns }\\n          data={ data }\\n          getRowId={ (row) => row.uuid }\\n          loading={ isLoading }\\n          stickyHeader>\\n          <DataTableHead />\\n\\n          <DataTableBody />\\n\\n          <DataTableEmpty>\\n            No result found.\\n          </DataTableEmpty>\\n        </DataTable>\\n      </div>\\n\\n      <Pagination\\n        className={ style['data-grid-with-query-filter__pagination'] }\\n        onPageChange={ ({ page }) => setCurrentPage(page) }\\n        page={ currentPage }\\n        pageSize={ PAGE_SIZE }\\n        totalItems={ total } />\\n    </div>\\n  );\\n};\\n\\nexport {\\n  DataGridWithQueryFilter,\\n};\\n"},"README.md":"# Data Grid With Query Filter\\n\\nTODO\\n"}},"email-field":{"name":"Email Field","reactTag":"EmailField","tags":["form","interactive"],"odsComponents":["FormField","FormFieldHelper","FormFieldLabel","FormFieldLabelSubLabel","Input","Select","SelectContent","SelectControl","TEXT_PRESET","Text"],"source":{"css-modules":{"index.module.scss":".email-field {\\n  &__field {\\n    display: grid;\\n    grid-template-columns: 1fr max-content 1fr;\\n    align-items: center;\\n\\n    &__input {\\n      z-index: 1;\\n      border-top-right-radius: 0;\\n      border-bottom-right-radius: 0;\\n    }\\n\\n    &__at {\\n      display: flex;\\n      align-items: center;\\n      justify-content: center;\\n      background-color: var(--ods-theme-background-color-readonly);\\n      width: 30px;\\n      height: 100%;\\n    }\\n\\n    &__select {\\n      border-top-left-radius: 0;\\n      border-bottom-left-radius: 0;\\n    }\\n  }\\n\\n  &__helper {\\n    &__list {\\n      margin: 0;\\n      padding: 0 calc(var(--ods-theme-padding-horizontal) * 2);\\n    }\\n  }\\n}\\n","index.tsx":"import { FormField, FormFieldHelper, FormFieldLabel, FormFieldLabelSubLabel, Input, Select, SelectContent, SelectControl, TEXT_PRESET, Text } from '@ovhcloud/ods-react';\\nimport { type JSX } from 'react';\\nimport style from './index.module.scss';\\n\\nconst DOMAINS = [\\n  { label: '.fr', value: '.fr' },\\n  { label: '.com', value: '.com' },\\n  { label: '.dev', value: '.dev' },\\n];\\n\\nconst EmailField = (): JSX.Element => {\\n  return (\\n    <FormField>\\n      <FormFieldLabel>\\n        Email\\n        <FormFieldLabelSubLabel>- mandatory</FormFieldLabelSubLabel>\\n      </FormFieldLabel>\\n\\n      <div className={ style['email-field__field'] }>\\n        <Input\\n          className={ style['email-field__field__input'] }\\n          name=\\"account-name\\"\\n          pattern=\\"^([a-zA-Z0-9]|([._\\\\-](?![._\\\\-])))*[a-zA-Z0-9]$\\"\\n          placeholder=\\"Account name\\" />\\n\\n        <Text\\n          className={ style['email-field__field__at'] }\\n          preset={ TEXT_PRESET.span }>\\n          @\\n        </Text>\\n\\n        <Select\\n          items={ DOMAINS }\\n          name=\\"domain\\">\\n          <SelectControl\\n            className={ style['email-field__field__select'] }\\n            placeholder=\\"Select domain\\" />\\n\\n          <SelectContent />\\n        </Select>\\n      </div>\\n\\n      <FormFieldHelper>\\n        <Text preset={ TEXT_PRESET.caption }>\\n          The part before the email address (the text before the @) must follow these guidelines:\\n          <ul className={ style['email-field__helper__list'] }>\\n            <li>It must end with a letter or a number</li>\\n            <li>Allowed special characters are: &quot;.&quot;, &quot;_&quot;, &quot;-&quot;</li>\\n            <li>Special characters cannot be placed next to each other</li>\\n          </ul>\\n        </Text>\\n      </FormFieldHelper>\\n    </FormField>\\n  );\\n};\\n\\nexport {\\n  EmailField,\\n};\\n"},"README.md":"# Email Field\\n\\nThe Email Field helps users enter an email address more accurately by splitting it into two dedicated input fields\\nseparated by a read-only \\"@\\", clarifying the expected format and reducing input mistakes.\\n"}},"feature-list":{"name":"Feature List","reactTag":"FeatureList","tags":["presentation"],"odsComponents":["ICON_NAME","Icon","TEXT_PRESET","Text","Tooltip","TooltipContent","TooltipTrigger"],"source":{"css-modules":{"index.module.scss":".feature-list {\\n  display: flex;\\n  flex-flow: column;\\n  row-gap: var(--ods-theme-row-gap);\\n  margin: 0;\\n  padding: 0;\\n  list-style: none;\\n\\n  &__item {\\n    display: flex;\\n    flex-flow: row;\\n    column-gap: calc(var(--ods-theme-column-gap) / 2);\\n    align-items: baseline;\\n\\n    &__icon {\\n      color: var(--ods-theme-success-color);\\n    }\\n\\n    &__tooltip-trigger {\\n      margin-left: calc(var(--ods-theme-column-gap) / 2);\\n      color: var(--ods-theme-primary-color);\\n    }\\n  }\\n}\\n","index.tsx":"import { ICON_NAME, Icon, TEXT_PRESET, Text, Tooltip, TooltipContent, TooltipTrigger } from '@ovhcloud/ods-react';\\nimport { type JSX } from 'react';\\nimport style from './index.module.scss';\\n\\nconst FEATURES = [\\n  { label: 'Memory: up to 1.5 TB' },\\n  { label: 'SLA: 99.99%' },\\n  { label: 'Guaranteed public bandwidth from 5 Gbps to 25 Gbps', tooltipContent: 'Except for our Asia-Pacific regions.' },\\n  { label: '25 Gbps private bandwidth included' },\\n  { label: 'OVHcloud Link Aggregation' },\\n];\\n\\nconst FeatureList = (): JSX.Element => {\\n  return (\\n    <ul className={ style['feature-list'] }>\\n      {\\n        FEATURES.map(({ label, tooltipContent }, idx) => (\\n          <li\\n            className={ style['feature-list__item'] }\\n            key={ idx }>\\n            <Icon\\n              className={ style['feature-list__item__icon'] }\\n              name={ ICON_NAME.check } />\\n\\n            <div>\\n              <Text preset={ TEXT_PRESET.span }>\\n                { label }\\n              </Text>\\n\\n              {\\n                !!tooltipContent &&\\n                <Tooltip>\\n                  <TooltipTrigger asChild>\\n                    <Icon\\n                      className={ style['feature-list__item__tooltip-trigger'] }\\n                      name={ ICON_NAME.circleQuestion } />\\n                  </TooltipTrigger>\\n\\n                  <TooltipContent>\\n                    { tooltipContent }\\n                  </TooltipContent>\\n                </Tooltip>\\n              }\\n            </div>\\n          </li>\\n        ))\\n      }\\n    </ul>\\n  );\\n};\\n\\nexport {\\n  FeatureList,\\n};\\n"},"README.md":"# Feature List\\n\\nThe Feature List is used to display concise product capabilities with a check indicator and optional tooltip,\\nproviding users with a quick, inline overview of what is included.\\n"}},"feature-list-product-card":{"name":"Feature List Product Card","reactTag":"FeatureListProductCard","tags":["cart","interactive","presentation","product"],"odsComponents":["BADGE_COLOR","BADGE_SIZE","Badge","CARD_COLOR","Card","ICON_NAME","Icon","Link","Select","SelectContent","SelectControl","TEXT_PRESET","Text","Tooltip","TooltipContent","TooltipTrigger","formatPrice"],"source":{"css-modules":{"index.module.scss":"@use '@ovhcloud/ods-react/style';\\n\\n.feature-list-product-card {\\n  overflow: hidden;\\n\\n  &__info,\\n  &__features,\\n  &__footer {\\n    padding: calc(var(--ods-theme-padding-vertical) * 2) calc(var(--ods-theme-padding-horizontal) * 2);\\n  }\\n\\n  &__info {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: calc(var(--ods-theme-row-gap) * 2);\\n\\n    &__badges {\\n      display: flex;\\n      flex-flow: row;\\n      gap: var(--ods-theme-row-gap) var(--ods-theme-column-gap);\\n    }\\n\\n    &__description {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: var(--ods-theme-row-gap);\\n    }\\n\\n    &__pricing {\\n      display: flex;\\n      flex-flow: column;\\n\\n      &__from {\\n        color: var(--ods-theme-text-color);\\n        font-size: 18px;\\n        font-weight: 700;\\n      }\\n\\n      &__price {\\n        display: flex;\\n        flex-flow: row;\\n        column-gap: var(--ods-theme-column-gap);\\n        align-items: baseline;\\n\\n        &__amount {\\n          color: var(--ods-theme-primary-color);\\n          font-size: 36px;\\n          font-weight: 700;\\n        }\\n      }\\n\\n      &__duration {\\n        font-weight: 600;\\n      }\\n    }\\n\\n    &__details {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: calc(var(--ods-theme-row-gap) / 2);\\n\\n      &__installation {\\n        display: flex;\\n        flex-flow: row;\\n        column-gap: calc(var(--ods-theme-column-gap) / 2);\\n      }\\n    }\\n\\n    &__order {\\n      $primary-color: #ff0004;\\n      $button: &;\\n\\n      --order-button-color-active: var(--ods-color-critical-700);\\n      --order-button-color-hover: var(--ods-color-critical-500);\\n      --order-button-text-color: #fff;\\n\\n      display: flex;\\n      flex-flow: row;\\n      column-gap: calc(var(--ods-theme-column-gap) * 2);\\n      align-items: center;\\n      align-self: center;\\n      border: 0;\\n      border-radius: var(--ods-theme-border-radius);\\n      padding: calc(var(--ods-theme-padding-vertical) / 2) calc(var(--ods-theme-column-gap) * 2) calc(var(--ods-theme-padding-vertical) / 2) calc(var(--ods-theme-padding-horizontal) / 2);\\n      font-size: 16px;\\n      font-weight: 600;\\n\\n      &:disabled {\\n        background: var(--ods-theme-background-color-disabled);\\n        color: var(--ods-theme-text-color-disabled);\\n\\n        #{$button}__icon {\\n          color: var(--ods-theme-text-color-disabled);\\n        }\\n      }\\n\\n      &:focus-visible {\\n        @include style.ods-focus();\\n      }\\n\\n      &:not(:disabled) {\\n        transition: background ease .3s, box-shadow ease .3s;\\n        box-shadow: -3px -3px 6px 0 #ff4800 inset, 3px 3px 6px 0 #ea0000 inset, -3px -3px 6px 0 #ffd2d2b2, 3px 3px 6px 0 #82000040;\\n        background: $primary-color linear-gradient(86.59deg, rgba(255, 187, 0, 0) 82.69%, rgba(255, 187, 0, 0.75) 100%);\\n        cursor: pointer;\\n        color: var(--order-button-text-color);\\n\\n        &:focus-visible,\\n        &:hover {\\n          box-shadow: none;\\n          background: var(--order-button-color-hover);\\n\\n          #{$button}__icon {\\n            box-shadow: none;\\n            color: var(--order-button-color-hover);\\n          }\\n        }\\n\\n        &:active {\\n          box-shadow: none;\\n          background: var(--order-button-color-active);\\n\\n          #{$button}__icon {\\n            box-shadow: none;\\n            color: var(--order-button-color-active);\\n          }\\n        }\\n\\n        #{$button}__icon {\\n          box-shadow: 3px 3px 6px 0 #82000040 inset, -3px -3px 6px 0 #ffd2d2b2 inset;\\n        }\\n      }\\n\\n      &__icon {\\n        border-radius: calc(var(--ods-theme-border-radius) * .75);\\n        background-color: var(--order-button-text-color);\\n        padding: var(--ods-theme-padding-vertical) var(--ods-theme-padding-horizontal);\\n        color: $primary-color;\\n        font-size: 18px;\\n      }\\n    }\\n  }\\n\\n  &__features {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: calc(var(--ods-theme-row-gap) * 2);\\n    margin: 0;\\n    list-style: none;\\n\\n    &__section {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: var(--ods-theme-row-gap);\\n\\n      &__item {\\n        &__tooltip-trigger {\\n          margin-left: calc(var(--ods-theme-column-gap) / 2);\\n          color: var(--ods-theme-primary-color);\\n        }\\n      }\\n\\n      &__items {\\n        display: flex;\\n        flex-flow: column;\\n        row-gap: var(--ods-theme-row-gap);\\n        margin: 0;\\n        padding: 0;\\n        list-style: none;\\n\\n        &__item {\\n          display: flex;\\n          flex-flow: row;\\n          column-gap: calc(var(--ods-theme-column-gap) / 2);\\n          align-items: baseline;\\n\\n          &__tooltip-trigger {\\n            margin-left: calc(var(--ods-theme-column-gap) / 2);\\n            color: var(--ods-theme-primary-color);\\n          }\\n\\n          &__icon {\\n            color: var(--ods-theme-success-color);\\n          }\\n        }\\n      }\\n    }\\n  }\\n\\n  &__features,\\n  &__footer {\\n    background-color: var(--ods-theme-background-color-readonly);\\n  }\\n}\\n","index.tsx":"import { BADGE_COLOR, BADGE_SIZE, Badge, CARD_COLOR, Card, ICON_NAME, Icon, Link, Select, SelectContent, SelectControl, TEXT_PRESET, Text, Tooltip, TooltipContent, TooltipTrigger, formatPrice } from '@ovhcloud/ods-react';\\nimport { type JSX, useState } from 'react';\\nimport style from './index.module.scss';\\n\\nconst FEATURES = [{\\n  items: [\\n    { label: 'Unlimited websites', tooltipContent: 'Some details.' },\\n    { label: 'High power level' },\\n    { label: '1 domain name free for the first', tooltipContent: 'Some details.' },\\n    { label: '500 GB SSD storage', tooltipContent: 'Some details.' },\\n    { label: '1,000 email addresses', tooltipContent: 'Some details.' },\\n  ],\\n  title: '',\\n}, {\\n  items: [\\n    { label: 'WordPress' },\\n    { label: 'Joomla!' },\\n    { label: 'Drupal' },\\n    { label: 'Prestashop' },\\n  ],\\n  title: '1-click CMS',\\n  tooltipContent: 'Some details.',\\n}, {\\n  items: [\\n    { label: '4 x 1 GB databases' },\\n    { label: '8 GB Web Cloud Databases', tooltipContent: 'Some details.' },\\n  ],\\n  title: 'Database',\\n  tooltipContent: 'Some details.',\\n}, {\\n  items: [\\n    { label: 'Unlimited free SSL', tooltipContent: 'Some details.' },\\n    { label: 'Anti-DDoS protection' },\\n    { label: 'Anti-virus and anti-spam' },\\n    { label: 'Daily backups', tooltipContent: 'Some details.' },\\n  ],\\n  title: 'Security',\\n}, {\\n  items: [\\n    { label: '99.9% observed availability' },\\n    { label: 'Guaranteed resources', tooltipContent: 'Some details.' },\\n    { label: 'Unlimited traffic' },\\n    { label: 'Service continuity', tooltipContent: 'Some details.' },\\n    { label: 'Boost option to withstand temporary traffic spikes', tooltipContent: 'Some details.' },\\n  ],\\n  title: 'Performance',\\n}, {\\n  items: [\\n    { label: 'Git' },\\n    { label: 'Standard support' },\\n    { label: 'SSH access' },\\n    { label: 'CDN Basic' },\\n  ],\\n  title: 'Support and additional services',\\n}];\\n\\nconst HOSTING_ITEMS = [\\n  { label: '1 vCore 2,4 GHz, 2 Go RAM', value:'hosting-1' },\\n  { label: '1 vCore 2,4 GHz, 4 Go RAM', value:'hosting-2' },\\n  { label: '2 vCores 2,4 GHz, 8 Go RAM', value:'hosting-3' },\\n];\\n\\nconst FeatureListProductCard = (): JSX.Element => {\\n  const [isOrderButtonFocused, setIsOrderButtonFocused] = useState(false);\\n  const [isOrderButtonHovered, setIsOrderButtonHovered] = useState(false);\\n\\n  return (\\n    <Card\\n      className={ style['feature-list-product-card'] }\\n      color={ CARD_COLOR.neutral }>\\n      <div className={ style['feature-list-product-card__info'] }>\\n        <Text preset={ TEXT_PRESET.span }>\\n          WEB HOSTING\\n        </Text>\\n\\n        <div className={ style['feature-list-product-card__info__badges'] }>\\n          <Badge\\n            color={ BADGE_COLOR.new }\\n            size={ BADGE_SIZE.sm }>\\n            New\\n          </Badge>\\n\\n          <Badge\\n            color={ BADGE_COLOR.information }\\n            size={ BADGE_SIZE.sm }>\\n            Best seller\\n          </Badge>\\n        </div>\\n\\n        <div className={ style['feature-list-product-card__info__description'] }>\\n          <Text\\n            as=\\"span\\"\\n            preset={ TEXT_PRESET.heading2 }>\\n            Performance\\n          </Text>\\n\\n          <Text preset={ TEXT_PRESET.paragraph }>\\n            For demanding online stores and projects.\\n          </Text>\\n        </div>\\n\\n        <Select\\n          defaultValue={ ['hosting-1'] }\\n          items={ HOSTING_ITEMS }>\\n          <SelectControl placeholder=\\"Select option\\" />\\n\\n          <SelectContent />\\n        </Select>\\n\\n        <div className={ style['feature-list-product-card__info__pricing'] }>\\n          <span className={ style['feature-list-product-card__info__pricing__from'] }>\\n            From\\n          </span>\\n\\n          <div className={ style['feature-list-product-card__info__pricing__price'] }>\\n            <span className={ style['feature-list-product-card__info__pricing__price__amount'] }>\\n              { formatPrice(24.46, 'en-GB', 'EUR') }\\n            </span>\\n\\n            <Text\\n              as=\\"span\\"\\n              preset={ TEXT_PRESET.small }>\\n              ex. VAT/month\\n            </Text>\\n          </div>\\n\\n          <Text\\n            as=\\"span\\"\\n            preset={ TEXT_PRESET.small }>\\n            or €13.19 incl. VAT/month\\n          </Text>\\n\\n          <Text\\n            as=\\"span\\"\\n            className={ style['feature-list-product-card__info__pricing__duration'] }\\n            preset={ TEXT_PRESET.small }>\\n            for a 24-month registration\\n          </Text>\\n        </div>\\n\\n        <div className={ style['feature-list-product-card__info__details'] }>\\n          <Text\\n            as=\\"span\\"\\n            preset={ TEXT_PRESET.label }>\\n            Minimum 2-year registration\\n          </Text>\\n\\n          <Text\\n            as=\\"span\\"\\n            preset={ TEXT_PRESET.heading6 }>\\n            <Badge color={ BADGE_COLOR.promotion }><Icon name={ ICON_NAME.tag } /></Badge> €100 free with a 5-year registration\\n          </Text>\\n\\n          <div className={ style['feature-list-product-card__info__details__installation'] }>\\n            <Text preset={ TEXT_PRESET.span }>\\n              Installation fee:\\n            </Text>\\n\\n            <Text\\n              as=\\"span\\"\\n              preset={ TEXT_PRESET.heading6 }>\\n              Free\\n            </Text>\\n          </div>\\n        </div>\\n\\n        <button\\n          className={ style['feature-list-product-card__info__order'] }\\n          onBlur={ () => setIsOrderButtonFocused(false) }\\n          onFocus={ () => setIsOrderButtonFocused(true) }\\n          onMouseEnter={ () => setIsOrderButtonHovered(true) }\\n          onMouseLeave={ () => setIsOrderButtonHovered(false) }\\n          type=\\"button\\">\\n          <Icon\\n            className={ style['feature-list-product-card__info__order__icon'] }\\n            name={ isOrderButtonFocused || isOrderButtonHovered ? ICON_NAME.shoppingCartPlus : ICON_NAME.shoppingCart } />\\n          Order now\\n        </button>\\n      </div>\\n\\n      <ul className={ style['feature-list-product-card__features'] }>\\n        {\\n          FEATURES.map(({ items, title, tooltipContent }, idx) => (\\n            <li\\n              className={ style['feature-list-product-card__features__section'] }\\n              key={ idx }>\\n              {\\n                title &&\\n                <div className={ style['feature-list-product-card__features__section__item'] }>\\n                  <Text\\n                    as=\\"span\\"\\n                    preset={ TEXT_PRESET.label }>\\n                    { title }\\n                  </Text>\\n\\n                  {\\n                    !!tooltipContent &&\\n                    <Tooltip>\\n                      <TooltipTrigger asChild>\\n                        <Icon\\n                          className={ style['feature-list-product-card__features__section__item__tooltip-trigger'] }\\n                          name={ ICON_NAME.circleQuestion } />\\n                      </TooltipTrigger>\\n\\n                      <TooltipContent>\\n                        { tooltipContent }\\n                      </TooltipContent>\\n                    </Tooltip>\\n                  }\\n                </div>\\n              }\\n\\n              <ul className={ style['feature-list-product-card__features__section__items'] }>\\n                {\\n                  items.map(({ label, tooltipContent }, idx) => (\\n                    <li\\n                      className={ style['feature-list-product-card__features__section__items__item'] }\\n                      key={ idx }>\\n                      <Icon\\n                        className={ style['feature-list-product-card__features__section__items__item__icon'] }\\n                        name={ ICON_NAME.check } />\\n\\n                      <div>\\n                        <Text preset={ TEXT_PRESET.span }>\\n                          { label }\\n                        </Text>\\n\\n                        {\\n                          !!tooltipContent &&\\n                          <Tooltip>\\n                            <TooltipTrigger asChild>\\n                              <Icon\\n                                className={ style['feature-list-product-card__features__section__items__item__tooltip-trigger'] }\\n                                name={ ICON_NAME.circleQuestion } />\\n                            </TooltipTrigger>\\n\\n                            <TooltipContent>\\n                              { tooltipContent }\\n                            </TooltipContent>\\n                          </Tooltip>\\n                        }\\n                      </div>\\n                    </li>\\n                  ))\\n                }\\n              </ul>\\n            </li>\\n          ))\\n        }\\n      </ul>\\n\\n      <div className={ style['feature-list-product-card__footer'] }>\\n        <Link href=\\"#\\">\\n          View product <Icon name={ ICON_NAME.arrowRight } />\\n        </Link>\\n      </div>\\n    </Card>\\n  );\\n};\\n\\nexport {\\n  FeatureListProductCard,\\n};\\n"},"README.md":"# Feature List Product Card\\n\\nThe Feature List Product Card is a rich, vertical and detailed product presentation card used for comparing products or\\nproviding in-depth information. It displays structured content in a vertical layout: category, badges, title, subtitle,\\nproduct description, a Select component for configuration, pricing details (including taxes, duration, and promotional\\nconditions), an action button, and a detailed feature list with check icon indicating included items. A link completes\\nthe card for additional information.\\n\\nUse this card when you need to help users evaluate a product in detail, compare features, understand pricing, or select\\na product variant before taking action. It is suitable for catalog pages, comparison tools, and purchase funnels.\\n"}},"media-product-card":{"name":"Media Product Card","reactTag":"MediaProductCard","tags":["product","presentation"],"odsComponents":["CARD_COLOR","Card","ICON_NAME","Icon","Link","Medium","TEXT_PRESET","Text"],"source":{"css-modules":{"index.module.scss":".media-product-card {\\n  overflow: hidden;\\n\\n  &__body {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: calc(var(--ods-theme-row-gap) * 3);\\n    padding: calc(var(--ods-theme-padding-vertical) * 2) calc(var(--ods-theme-padding-horizontal) * 2);\\n\\n    &__logo {\\n      align-self: center;\\n    }\\n\\n    &__content {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: calc(var(--ods-theme-row-gap) * 2);\\n    }\\n  }\\n\\n  &__footer {\\n    background-color: var(--ods-theme-background-color-readonly);\\n    padding: calc(var(--ods-theme-padding-vertical) * 2) calc(var(--ods-theme-padding-horizontal) * 2);\\n  }\\n}\\n","index.tsx":"import { CARD_COLOR, Card, ICON_NAME, Icon, Link, Medium, TEXT_PRESET, Text } from '@ovhcloud/ods-react';\\nimport { type JSX } from 'react';\\nimport logoUrl from '../assets/product.png';\\nimport style from './index.module.scss';\\n\\nconst MediaProductCard = (): JSX.Element => {\\n  return (\\n    <Card\\n      className={ style['media-product-card'] }\\n      color={ CARD_COLOR.neutral }>\\n      <div className={ style['media-product-card__body'] }>\\n        <Medium\\n          alt=\\"AI Deploy logo\\"\\n          className={ style['media-product-card__body__logo'] }\\n          height={ 174 }\\n          src={ logoUrl }\\n          width={ 174 } />\\n\\n        <div className={ style['media-product-card__body__content'] }>\\n          <Text\\n            as=\\"span\\"\\n            preset={ TEXT_PRESET.heading2 }>\\n            AI Deploy\\n          </Text>\\n\\n          <Text preset={ TEXT_PRESET.paragraph }>\\n            Easily deploy machine learning models and applications into production, create your API access points with ease, and make effective predictions.\\n          </Text>\\n        </div>\\n      </div>\\n\\n      <div className={ style['media-product-card__footer'] }>\\n        <Link href=\\"#\\">\\n          Discover AI Deploy <Icon name={ ICON_NAME.arrowRight } />\\n        </Link>\\n      </div>\\n    </Card>\\n  );\\n};\\n\\nexport {\\n  MediaProductCard,\\n};\\n"},"README.md":"# Media Product Card\\n\\nThe Media Product Card is used to quickly present a product with key information and a visual preview, offering users\\na clear action and an optional link to learn more.\\n\\nThe Media Product Card is a vertical compact product presentation card designed to provide essential information at a\\nglance. It displays an image, followed by a title, subtitle, and short description, along with an action button, and\\na link.\\n\\nUse this card when you want to showcase a product. It is suited for product listings, or anywhere users need a quick\\noverview with a clear path to learn more or take action.\\n"}},"order-button":{"name":"Order Button","reactTag":"OrderButton","tags":["cart","interactive"],"odsComponents":["ICON_NAME","Icon"],"source":{"css-modules":{"index.module.scss":"@use '@ovhcloud/ods-react/style';\\n\\n.order-button {\\n  $primary-color: #ff0004;\\n  $button: &;\\n\\n  --ods-recipe-order-button-color-active: var(--ods-color-critical-700);\\n  --ods-recipe-order-button-color-hover: var(--ods-color-critical-500);\\n  --ods-recipe-order-button-text-color: #fff;\\n\\n  display: flex;\\n  flex-flow: row;\\n  column-gap: calc(var(--ods-theme-column-gap) * 2);\\n  align-items: center;\\n  border: 0;\\n  border-radius: var(--ods-theme-border-radius);\\n  padding: calc(var(--ods-theme-padding-vertical) / 2) calc(var(--ods-theme-column-gap) * 2) calc(var(--ods-theme-padding-vertical) / 2) calc(var(--ods-theme-padding-horizontal) / 2);\\n  font-size: 16px;\\n  font-weight: 600;\\n\\n  &:disabled {\\n    background: var(--ods-theme-background-color-disabled);\\n    color: var(--ods-theme-text-color-disabled);\\n\\n    #{$button}__icon {\\n      color: var(--ods-theme-text-color-disabled);\\n    }\\n  }\\n\\n  &:focus-visible {\\n    @include style.ods-focus();\\n  }\\n\\n  &:not(:disabled) {\\n    transition: background ease .3s, box-shadow ease .3s;\\n    box-shadow: -3px -3px 6px 0 #ff4800 inset, 3px 3px 6px 0 #ea0000 inset, -3px -3px 6px 0 #ffd2d2b2, 3px 3px 6px 0 #82000040;\\n    background: $primary-color linear-gradient(86.59deg, rgba(255, 187, 0, 0) 82.69%, rgba(255, 187, 0, 0.75) 100%);\\n    cursor: pointer;\\n    color: var(--ods-recipe-order-button-text-color);\\n\\n    &:focus-visible,\\n    &:hover {\\n      box-shadow: none;\\n      background: var(--ods-recipe-order-button-color-hover);\\n\\n      #{$button}__icon {\\n        box-shadow: none;\\n        color: var(--ods-recipe-order-button-color-hover);\\n      }\\n    }\\n\\n    &:active {\\n      box-shadow: none;\\n      background: var(--ods-recipe-order-button-color-active);\\n\\n      #{$button}__icon {\\n        box-shadow: none;\\n        color: var(--ods-recipe-order-button-color-active);\\n      }\\n    }\\n\\n    #{$button}__icon {\\n      box-shadow: 3px 3px 6px 0 #82000040 inset, -3px -3px 6px 0 #ffd2d2b2 inset;\\n    }\\n  }\\n\\n  &__icon {\\n    border-radius: calc(var(--ods-theme-border-radius) * .75);\\n    background-color: var(--ods-recipe-order-button-text-color);\\n    padding: var(--ods-theme-padding-vertical) var(--ods-theme-padding-horizontal);\\n    color: $primary-color;\\n    font-size: 18px;\\n  }\\n}\\n","index.tsx":"import { ICON_NAME, Icon } from '@ovhcloud/ods-react';\\nimport { type JSX, useState } from 'react';\\nimport style from './index.module.scss';\\n\\ntype OrderButtonProp = {\\n  disabled?: boolean,\\n}\\n\\nconst OrderButton = ({ disabled }: OrderButtonProp): JSX.Element => {\\n  const [isFocused, setIsFocused] = useState(false);\\n  const [isHovered, setIsHovered] = useState(false);\\n\\n  function onBlur(): void {\\n    setIsFocused(false);\\n  }\\n\\n  function onFocus(): void {\\n    setIsFocused(true);\\n  }\\n\\n  function onMouseEnter(): void {\\n    setIsHovered(true);\\n  }\\n\\n  function onMouseLeave(): void {\\n    setIsHovered(false);\\n  }\\n\\n  return (\\n    <button\\n      className={ style['order-button'] }\\n      disabled={ disabled }\\n      onBlur={ onBlur }\\n      onFocus={ onFocus }\\n      onMouseEnter={ onMouseEnter }\\n      onMouseLeave={ onMouseLeave }\\n      type=\\"button\\">\\n      <Icon\\n        className={ style['order-button__icon'] }\\n        name={ isFocused || isHovered ? ICON_NAME.shoppingCartPlus : ICON_NAME.shoppingCart } />\\n      Order\\n    </button>\\n  );\\n};\\n\\nexport {\\n  OrderButton,\\n  type OrderButtonProp,\\n};\\n"},"README.md":"# Order Button\\n\\nThe Order Button is a prominent, cart-icon button used to initiate a purchase action, making it clear and easy for\\nusers to place an order.\\n"}},"range-input":{"name":"Range Input","reactTag":"RangeInput","tags":["form","interactive"],"odsComponents":["INPUT_TYPE","Input","Range","type RangeValueChangeDetail"],"source":{"css-modules":{"index.module.scss":".range-input {\\n  display: grid;\\n  grid-template-columns: 1fr min-content;\\n  column-gap: calc(var(--ods-theme-column-gap) * 2);\\n  align-items: baseline;\\n\\n  &__input {\\n    width: 60px;\\n  }\\n}\\n","index.tsx":"import { INPUT_TYPE, Input, Range, type RangeValueChangeDetail } from '@ovhcloud/ods-react';\\nimport { type ChangeEvent, type JSX, useState } from 'react';\\nimport style from './index.module.scss';\\n\\nconst MAX = 100;\\nconst MIN = 0;\\n\\nconst RangeInput = (): JSX.Element => {\\n  const [draggingValues, setDraggingValues] = useState([MIN]);\\n\\n  function onInputChange(event: ChangeEvent<HTMLInputElement>): void {\\n    setDraggingValues([Math.min(MAX, Math.abs(event.target.valueAsNumber))]);\\n  }\\n\\n  function onRangeDragging({ value }: RangeValueChangeDetail): void {\\n    setDraggingValues(value);\\n  }\\n\\n  return (\\n    <div className={ style['range-input'] }>\\n      <Range\\n        max={ MAX }\\n        min={ MIN }\\n        onDragging={ onRangeDragging }\\n        value={ draggingValues } />\\n\\n      <Input\\n        className={ style['range-input__input'] }\\n        max={ MAX }\\n        min={ MIN }\\n        onChange={ onInputChange }\\n        type={ INPUT_TYPE.number }\\n        value={ draggingValues[0] } />\\n    </div>\\n  );\\n};\\n\\nexport {\\n  RangeInput,\\n};\\n"},"tailwind":{"index.module.css":"/* stylelint-disable */\\n@tailwind base;\\n@tailwind components;\\n@tailwind utilities;\\n/* stylelint-enable */\\n","index.tsx":"import { INPUT_TYPE, Input, Range, type RangeValueChangeDetail } from '@ovhcloud/ods-react';\\nimport { type ChangeEvent, type JSX, useState } from 'react';\\nimport './index.module.css';\\n\\nconst MAX = 100;\\nconst MIN = 0;\\n\\nconst RangeInput = (): JSX.Element => {\\n  const [draggingValues, setDraggingValues] = useState([MIN]);\\n\\n  function onInputChange(event: ChangeEvent<HTMLInputElement>): void {\\n    setDraggingValues([Math.min(MAX, Math.abs(event.target.valueAsNumber))]);\\n  }\\n\\n  function onRangeDragging({ value }: RangeValueChangeDetail): void {\\n    setDraggingValues(value);\\n  }\\n\\n  return (\\n    <div className=\\"grid grid-cols-[1fr_min-content] gap-x-[calc(var(--ods-theme-column-gap)_*_2)] items-baseline\\">\\n      <Range\\n        max={ MAX }\\n        min={ MIN }\\n        onDragging={ onRangeDragging }\\n        value={ draggingValues } />\\n\\n      <Input\\n        className=\\"w-[60px]\\"\\n        max={ MAX }\\n        min={ MIN }\\n        onChange={ onInputChange }\\n        type={ INPUT_TYPE.number }\\n        value={ draggingValues[0] } />\\n    </div>\\n  );\\n};\\n\\nexport {\\n  RangeInput,\\n};\\n"},"README.md":"# Range Input\\n\\nThe Range Input is used to provide users with an intuitive way to set numeric values, allowing changes via the range\\nor input field while keeping both in sync for single range.\\n"}},"status-message":{"name":"Status Message","reactTag":"StatusMessage","tags":["interactive","status"],"odsComponents":["BUTTON_COLOR","BUTTON_SIZE","Button","ICON_NAME","MESSAGE_COLOR","Message","MessageBody","MessageIcon"],"source":{"css-modules":{"index.module.scss":".status-message {\\n  &__body {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: var(--ods-theme-row-gap);\\n\\n    &__content {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: calc(var(--ods-theme-row-gap) / 2);\\n\\n      &__title {\\n        font-weight: 700;\\n      }\\n\\n      &__message {\\n        margin: 0;\\n      }\\n    }\\n  }\\n}\\n","index.tsx":"import { BUTTON_COLOR, BUTTON_SIZE, Button, ICON_NAME, MESSAGE_COLOR, Message, MessageBody, MessageIcon } from '@ovhcloud/ods-react';\\nimport { type JSX } from 'react';\\nimport style from './index.module.scss';\\n\\nconst StatusMessage = (): JSX.Element => {\\n  return (\\n    <Message color={ MESSAGE_COLOR.information }>\\n      <MessageIcon name={ ICON_NAME.circleInfo } />\\n\\n      <MessageBody className={ style['status-message__body'] }>\\n        <div className={ style['status-message__body__content'] }>\\n          <span className={ style['status-message__body__content__title'] }>\\n            Activate your project and get €200 in free cloud credit\\n          </span>\\n\\n          <p className={ style['status-message__body__content__message'] }>\\n            You are currently in discovery mode. Activate your project to unlock your cloud resources and start building in minutes.\\n          </p>\\n        </div>\\n\\n        <div>\\n          <Button\\n            color={ BUTTON_COLOR.primary }\\n            size={ BUTTON_SIZE.xs }>\\n            Activate\\n          </Button>\\n        </div>\\n      </MessageBody>\\n    </Message>\\n  );\\n};\\n\\nexport {\\n  StatusMessage,\\n};\\n"},"tailwind":{"index.module.css":"/* stylelint-disable */\\n@tailwind base;\\n@tailwind components;\\n@tailwind utilities;\\n/* stylelint-enable */\\n","index.tsx":"import { BUTTON_COLOR, BUTTON_SIZE, Button, ICON_NAME, MESSAGE_COLOR, Message, MessageBody, MessageIcon } from '@ovhcloud/ods-react';\\nimport { type JSX } from 'react';\\nimport './index.module.css';\\n\\nconst StatusMessage = (): JSX.Element => {\\n  return (\\n    <Message color={ MESSAGE_COLOR.information }>\\n      <MessageIcon name={ ICON_NAME.circleInfo } />\\n\\n      <MessageBody className=\\"flex flex-col flex-nowrap gap-y-[var(--ods-theme-row-gap)]\\">\\n        <div className=\\"flex flex-col flex-nowrap gap-y-[calc(var(--ods-theme-row-gap)_/_2)]\\">\\n          <span className=\\"font-[700]\\">\\n            Activate your project and get €200 in free cloud credit\\n          </span>\\n\\n          <p className=\\"m-0\\">\\n            You are currently in discovery mode. Activate your project to unlock your cloud resources and start building in minutes.\\n          </p>\\n        </div>\\n\\n        <div>\\n          <Button\\n            color={ BUTTON_COLOR.primary }\\n            size={ BUTTON_SIZE.xs }>\\n            Activate\\n          </Button>\\n        </div>\\n      </MessageBody>\\n    </Message>\\n  );\\n};\\n\\nexport {\\n  StatusMessage,\\n};\\n"},"README.md":"# Status Message\\n\\nThe Status Message is used to share contextual information with users while offering an optional action.\\n\\n## Variants\\n\\n### Information\\n\\nThe Information Status Message is used to display non-blocking, contextual information to the user,\\naccompanied by an optional action they can take if needed.\\nIt includes a clear title, a descriptive text, and a button that allows the user to access additional details\\nor perform a secondary task. Use this pattern when you want to inform the user about something relevant but non-urgent,\\nwhile offering a convenient action that can help them continue or learn more.\\n\\nRecommended icon to use: \`ICON_NAME.circleInfo\`\\n\\nMessage variant to use: \`MESSAGE_COLOR.information\`\\n\\n### Success\\n\\nThe Success Status Message is used to confirm that an action, process, or task has been completed successfully.\\nIt includes a success title, an explanation of what worked, and a button that enables the user to perform a follow-up\\naction (e.g., \\"view results\\", \\"undo\\").\\n\\nRecommended icon to use: \`ICON_NAME.circleCheck\`\\n\\nMessage variant to use: \`MESSAGE_COLOR.success\`\\n\\n### Warning\\n\\nThe Warning Status Message is used to draw attention to situations that are unusual or potentially problematic but not\\ncritical. It contains a warning title, a description explaining the potential issue, and a button that allows the user\\nto review or fix the situation if needed. Use this Message when something is unusual or potentially problematic and\\nyou want to alert the user while giving an optional action to mitigate or investigate the issue.\\n\\nRecommended icon to use: \`ICON_NAME.triangleExclamation\`\\n\\nMessage variant to use: \`MESSAGE_COLOR.warning\`\\n\\n### Critical\\n\\nThe Critical Status Message signals an error or a blocking situation that requires immediate attention. It includes a\\nclear critical title, a description of what is wrong, and an action button that guides the user toward resolving the\\nissue (e.g., \\"retry\\", \\"contact support\\"). Use this pattern whenever the user must take corrective action, or when the\\nsystem encounters a severe problem that impacts functionality or data integrity.\\n\\nRecommended icon to use: \`ICON_NAME.hexagonExclamation\`\\n\\nMessage variant to use: \`MESSAGE_COLOR.critical\`\\n"}},"status-modal":{"name":"Status Modal","reactTag":"StatusModal","tags":["dialog","interactive","status"],"odsComponents":["BUTTON_VARIANT","Button","MODAL_COLOR","Modal","ModalBody","ModalContent","ModalHeader","type ModalOpenChangeDetail","ModalTrigger","TEXT_PRESET","Text"],"source":{"css-modules":{"index.module.scss":".status-modal {\\n  &__body {\\n    display: flex;\\n    flex-flow: column;\\n    row-gap: calc(var(--ods-theme-row-gap) * 3);\\n\\n    &__content {\\n      display: flex;\\n      flex-flow: column;\\n      row-gap: calc(var(--ods-theme-row-gap) * 2);\\n    }\\n\\n    &__actions {\\n      display: flex;\\n      column-gap: calc(var(--ods-theme-column-gap) * 2);\\n      justify-content: flex-end;\\n    }\\n  }\\n}\\n","index.tsx":"import { BUTTON_VARIANT, Button, MODAL_COLOR, Modal, ModalBody, ModalContent, ModalHeader, type ModalOpenChangeDetail, ModalTrigger, TEXT_PRESET, Text } from '@ovhcloud/ods-react';\\nimport { type JSX, useState } from 'react';\\nimport style from './index.module.scss';\\n\\nconst StatusModal = (): JSX.Element => {\\n  const [isOpen, setIsOpen] = useState(false);\\n\\n  function closeModal(): void {\\n    setIsOpen(false);\\n  }\\n\\n  function onOpenChange({ open }: ModalOpenChangeDetail): void {\\n    setIsOpen(open);\\n  }\\n\\n  function openModal(): void {\\n    setIsOpen(true);\\n  }\\n\\n  return (\\n    <Modal\\n      onOpenChange={ onOpenChange }\\n      open={ isOpen }>\\n      <ModalTrigger asChild>\\n        <Button onClick={ openModal }>\\n          Trigger Status Modal\\n        </Button>\\n      </ModalTrigger>\\n\\n      <ModalContent color={ MODAL_COLOR.information }>\\n        <ModalHeader>\\n          <Text\\n            as=\\"span\\"\\n            preset={ TEXT_PRESET.heading3 }>\\n            Change your password\\n          </Text>\\n        </ModalHeader>\\n\\n        <ModalBody className={ style['status-modal__body'] }>\\n          <div className={ style['status-modal__body__content'] }>\\n            <Text preset={ TEXT_PRESET.paragraph }>\\n              An email will be sent to the address example@ovhcloud.com with the procedure to follow in order to make this change.\\n            </Text>\\n          </div>\\n\\n          <div className={ style['status-modal__body__actions'] }>\\n            <Button\\n              onClick={ closeModal }\\n              variant={ BUTTON_VARIANT.ghost }>\\n              Cancel\\n            </Button>\\n\\n            <Button>\\n              Confirm\\n            </Button>\\n          </div>\\n        </ModalBody>\\n      </ModalContent>\\n    </Modal>\\n  );\\n};\\n\\nexport {\\n  StatusModal,\\n};\\n"},"README.md":"# Status Modal\\n\\n## Variants\\n\\n### Information\\n\\nThe Default Status Modal is used to briefly interrupt the flow to inform users of important details, confirm successful\\nactions, or draw attention to potential issues, offering them a clear choice to proceed or cancel.\\n\\n### Critical\\n\\nThe Critical Status Modal is used when the system must urgently warn the user about a severe issue or a potentially\\nrisky action. It contains a prominent title, an explanation of the critical situation, and two actions: a cancel button\\nand a critical action button guiding the user toward resolving or confirming the critical change.\\n\\nUse this modal when the user must make an explicit decision before proceeding, or when continuing without\\nacknowledgement could lead to negative consequences.\\n"}}}`),$h={components:["chat","config-tile","dashboard-card","data-grid","data-grid-with-query-filter","email-field","feature-list","feature-list-product-card","media-product-card","order-button","range-input","status-message","status-modal"]},nc={component:Ch,list:$h};functio